const QUESTIONS = [{"id": 1, "q": "日射の大気透過率は、大気中に含まれる水蒸気の量に影響される。", "answer": true, "exp": "大気中には、水蒸気や細かいチリがあって、特に水蒸気量によって日射量は大きく影響されて透過率を小さくし、夏には透過率は小さく、冬には大きくなります。"}, {"id": 2, "q": "天空日射とは、大気を通過して直接地表に到達する日射をいう。", "answer": false, "exp": "「天空日射」は、大気中の微粒子により散乱されたものが放射として地上にくるものです。"}, {"id": 3, "q": "日射のエネルギーは、紫外線部よりも赤外線部及び可視線部に多く含まれている。", "answer": true, "exp": "赤外線部と可視光線分で90％以上を占めます。"}, {"id": 4, "q": "太陽定数とは、大気上端で、太陽光線に対して垂直な面で受けた単位面積当たりの太陽放射エネルギーの強さをいう。", "answer": true, "exp": "単位時間あたりに、地球の大気圏外で太陽に正対する、単位面積に受ける太陽の日射総量を太陽定数といい、[kW/m2]が単位です。"}, {"id": 5, "q": "燃焼において、酸素濃度が18%近くに低下すると不完全燃焼が著しくなり、一酸化炭素の発生量が多くなる。", "answer": true, "exp": "燃焼において、「酸素濃度が18%近くに低下」すると「不完全燃焼」が著しくなり、「一酸化炭素」の発生量が多くなります。"}, {"id": 6, "q": "ホルムアルデヒド及び揮発性有機化合物（VOCS）のうちのいくつかは、発がん性物質である可能性が高いとされている。", "answer": true, "exp": "ホルムアルデヒド及び揮発性有機化合物（VOCS）のうちのいくつかは、発がん性物質である可能性が高いとされています。"}, {"id": 7, "q": "浮遊粉じんは、在室者の活動により、衣類の繊維、ほこり等が原因で発生し、その量は空気の乾燥によって減少する傾向がある。", "answer": false, "exp": "空気の乾燥によって「増加」する傾向にあります。"}, {"id": 8, "q": "臭気は、臭気強度や臭気指数で表され、空気汚染を知る指標とされている。", "answer": true, "exp": "ー"}, {"id": 9, "q": "CODは、主に水中に含まれる有機物を酸化剤で化学的に酸化したときに消費される酸素量である。", "answer": true, "exp": "主に水中に含まれる有機物を酸化剤で化学的に酸化したときに消費される酸素量をさします。"}, {"id": 10, "q": "DOは、水中に存在する有機物に含まれる炭素量のことで、水中の総炭素量から無機性炭素量を差し引いて求める。", "answer": false, "exp": "DO（Dissolved Oxygen ）とは、大気中から水に溶け込んでいる酸素(O₂) の量のことをさします。\nDOが高いほど水質が良いこととなります。"}, {"id": 11, "q": "大腸菌は、病原菌が存在する可能性を示す指標として用いられている。", "answer": true, "exp": "大腸菌は、病原菌が存在する可能性を示す指標として用いられています。"}, {"id": 12, "q": "SSは、浮遊物質量のことで、水の汚濁度を視覚的に判断する指標として使用される。", "answer": true, "exp": "SS（Suspended Solid）とは、浮遊物質量のことであり、水中に浮遊もしくは懸濁している直径２ｍｍ 以下の物質の量を表します。"}, {"id": 13, "q": "密閉容器内に静止している流体の一部に加えた圧力は、流体のすべての部分にそのまま伝わる。", "answer": true, "exp": "密閉容器内に静止している流体の一部に加えた圧力は、流体のすべての部分にそのまま伝わる、これは「パスカルの原理」によるものです。"}, {"id": 14, "q": "管路に流れる液体の密度が小さいほど、管路閉止時の水撃圧は高くなる。", "answer": false, "exp": "管路閉止時の水撃圧は、管路に流れる液体の密度が「大きい」ほど高くなります。"}, {"id": 15, "q": "ニュートン流体とは、粘性による摩擦応力が速度勾配に比例する流体をいう。", "answer": true, "exp": "「ニュートン流体」に関して、粘性による「摩擦応力」が「速度勾配」に「比例する」流体をいいます。"}, {"id": 16, "q": "レイノルズ数は、流体に作用する慣性力と粘性力の比で表される無次元数で、流体の平均流速に比例する", "answer": true, "exp": "「レイノルズ数」に関して流体に作用する「慣性力」と「粘性力」の比で表される無次元数で、「流体の平均流速」に「比例」します。"}, {"id": 17, "q": "異なる２種類の金属線を両端で接合した回路において、２つの接合点に温度差を与えると、熱起電力が生じる。", "answer": true, "exp": "「熱起電力」に関して述べており、本文のとおり異なる２種類の金属線を両端で接合した回路において、２つの接合点に温度差を与えると熱起電力が生じます。"}, {"id": 18, "q": "エンタルピーは、物質の持つエネルギーの状態量の一つで、その物質の内部エネルギーに、外部への体積膨張仕事量を加えたもので表される。", "answer": true, "exp": "エンタルピーとは物質の持つエネルギーの状態量の一つで、その物質の「内部エネルギー」に、「外部への体積膨張仕事量」を「加えた」もので表されます。"}, {"id": 19, "q": "融解熱、気化熱等のように、状態変化のみに費やされる熱を潜熱という。", "answer": true, "exp": "「潜熱」は融解熱、気化熱等のように、状態変化のみに費やされる熱をさします。これに関連するのは「顕熱」で、温度を変化させるための熱になります。"}, {"id": 20, "q": "気体の定圧比熱と定容比熱を比べると、常に定容比熱の方が大きい。", "answer": false, "exp": "定圧比熱とは、膨張する体積に制限をかけないときの気体の温度を1℃上昇させるのに必要な熱量です。\n定容比熱とは、膨張する体積に制限をかけた場合の気体の温度を1℃上昇させるのに必要な熱量です。\n膨張にエネルギーが遮られる定容比熱のほうが小さいということです。"}, {"id": 21, "q": "ボイラーの燃焼において、空気過剰率が大きいほど熱損失は小さくなる。", "answer": false, "exp": "空気過剰率が大きいほど、熱損失はおおきくなります。余剰分の空気の燃焼に熱量が奪われるからです。"}, {"id": 22, "q": "燃焼ガス中の窒素酸化物の量は、低温燃焼時よりも高温燃焼時の方が多い。", "answer": true, "exp": "燃焼ガス中の「窒素酸化物の量」は、低温燃焼時よりも「高温燃焼時の方が多い」です。"}, {"id": 23, "q": "不完全燃焼時における燃焼ガスには、二酸化炭素、水蒸気、窒素酸化物のほか、一酸化炭素等が含まれている。", "answer": true, "exp": "不完全燃焼時における燃焼ガスには、二酸化炭素、水蒸気、窒素酸化物のほか、「一酸化炭素」等が含まれています。"}, {"id": 24, "q": "低発熱量とは、高発熱量から潜熱分を差し引いた熱量をいう。", "answer": true, "exp": "低発熱量＝高発熱量　-　潜熱分（化学変化に必要な熱量）です。"}, {"id": 25, "q": "飽和湿り空気の温度を上げると、相対湿度は低下する。", "answer": true, "exp": "空気の温度が高くなるほど、同じ水分量でも湿度は下がるということです。"}, {"id": 26, "q": "飽和湿り空気の温度を下げると、絶対湿度は低下する。", "answer": true, "exp": "温度を下げると、空気中に含める水蒸気の量（絶対湿度）が減るという意味です。"}, {"id": 27, "q": "湿り空気を蒸気スプレーで加湿すると、絶対湿度と相対湿度はともに上昇するが、湿球温度は変わらない。", "answer": false, "exp": "「蒸気スプレーで加湿する」＝温度も湿度も「上がる」さらに湿球温度も「上がる」です。もし、これが水スプレーなら湿度は上がるが、温度は下がる、です。"}, {"id": 28, "q": "湿り空気をその露点温度より高い温度の冷却コイルで冷却しても、絶対湿度は変わらない。", "answer": true, "exp": "結露が起きない範囲で冷やしているだけなら、水蒸気の量は減らないという意味です。"}, {"id": 29, "q": "異種金属の接触腐食は、貴な金属と卑な金属を水中で組み合わせた場合、それぞれの電極電位差によって卑な金属が腐食する現象である。", "answer": true, "exp": "ー"}, {"id": 30, "q": "水中における炭素鋼の腐食は、pH４以下では、ほとんど起こらない。", "answer": false, "exp": "酸性が強いほど腐食しやすい"}, {"id": 31, "q": "溶存酸素の供給が多い開放系配管における配管用炭素鋼鋼管の腐食速度は、水温の上昇とともに80℃位までは増加する。", "answer": true, "exp": "「溶存酸素の供給が多い」ということは酸素が多く溶け込んでおり、水温の上昇の際の化学変化に多分に影響するのでこ"}, {"id": 32, "q": "配管用炭素鋼鋼管の腐食速度は、管内流速が速くなると増加するが、ある流速域では表面の不動態化が促進され腐食速度が減少する。", "answer": true, "exp": "管内流速が速くなると増加するのですが、、ある流速域に入ると、表面の「不動態化」が促進され、腐食速度が減少します。"}, {"id": 33, "q": "インバータによる運転は、電圧波形にひずみを含むため、インバータを用いない運転よりも電動機の温度が高くなる。", "answer": true, "exp": "インバータを使用し回転数を変えて電動機を運転すると、電動機への出力電圧波形に歪みを含み、電動機の温度が高くなります。"}, {"id": 34, "q": "スターデルタ始動方式は、全電圧直入始動方式と比較して、始動電流を 1/√3 に低減できる。", "answer": false, "exp": "始動電圧を1/3にできる"}, {"id": 35, "q": "トップランナーモータは、銅損低減のため抵抗を低くしている場合があり、標準モータに比べて始動電流が大きくなる傾向がある。", "answer": true, "exp": "モータの消費電量を減少させて省エネルギーに貢献するモータが、トップランナーモータです。"}, {"id": 36, "q": "インバータで運転すると、騒音が増加することがある。", "answer": true, "exp": "可変速運転時には、固有振動による共振が起こり、回転体がアンバランスとなって、異常振動が起こることがあるため、バランスの修正が必要です。"}, {"id": 37, "q": "乾燥した場所に敷設した合成樹脂製可とう管（ PF管 ）内には、電線の接続部を設けてもよい。", "answer": false, "exp": "乾燥した場所だろうと合成樹脂製可とう管（ PF管 ）内には、電線の接続部を設けてはいけません。"}, {"id": 38, "q": "使用電圧が300 V以下の金属管には、D種接地工事を施す。", "answer": true, "exp": "接地工事に関して、使用電圧が「300 V以下」の金属管には、「D種接地工事」です。「300Vをこえる」場合はC種接地工事になります。"}, {"id": 39, "q": "合成樹脂製可とう管（ PF管 ）相互の接続は、直接接続としてはならない。", "answer": true, "exp": "合成樹脂製可とう管（ PF管 ）相互の接続は、直接接続としてはいけません。"}, {"id": 40, "q": "金属管相互は、堅ろうに、かつ、電気的に完全に接続しなければならない。", "answer": true, "exp": "金属管相互は、堅ろうに、かつ、電気的に完全に接続しなければなりません。"}, {"id": 41, "q": "柱、梁の鉄筋のかぶり厚さとは、コンクリート表面から最も外部側に位置する帯筋、あばら筋等の表面までの最短距離をいう。", "answer": true, "exp": "ー"}, {"id": 42, "q": "耐力壁の鉄筋のかぶり厚さは、柱、梁のかぶり厚さと同じ厚さとする。", "answer": true, "exp": "ー"}, {"id": 43, "q": "基礎の鉄筋のかぶり厚さは、捨てコンクリート部分を含めた厚さとする。", "answer": false, "exp": "ー"}, {"id": 44, "q": "鉄筋の定着長さは、鉄筋径により異なる。", "answer": true, "exp": "鉄筋径の30～45倍の長さを必要とするため鉄筋径が大きくなるほど長くなります。"}, {"id": 45, "q": "構造部材に生じる応力は、軸方向応力、曲げモーメントの２種類である。", "answer": false, "exp": "構造部材に生じる応力は、「軸方向応力」、「曲げモーメント」以外にも「せん断力」や「引張力」があります。"}, {"id": 46, "q": "単位水量が多いほど、乾燥収縮によるひび割れが発生しやすい。", "answer": true, "exp": "単位水量が多いコンクリートほど、乾燥収縮による水分の損失が大きいのでひび割れが発生しやすいです。"}, {"id": 47, "q": "躯体を打設するコンクリートは、設計基準強度を割り増した強度とする。", "answer": true, "exp": "躯体を打設するコンクリートは、設計基準強度を割り増した強度とします。"}, {"id": 48, "q": "水セメント比を小さくすると、コンクリートの耐久性は高くなる。", "answer": true, "exp": "水セメント比を小さくすると、コンクリートの耐久性は高くなります。"}, {"id": 49, "q": "二重効用の吸収冷凍機は、低温再生器と高温再生器を設けるため、必要とする加熱量が少なく、単効用に比べて成績係数が高い。", "answer": true, "exp": "二重効用の吸収冷凍機は、単効用に対して「高温再生器」を追加したもので、本文のとおり必要とする加熱量が少なく、単効用に比べて成績係数が高いです。"}, {"id": 50, "q": "ロータリー冷凍機は、圧縮機の構造が簡単で、往復動冷凍機に比べて振動が小さい。", "answer": true, "exp": "ロータリー冷凍機はロータの回転による遠心力を利用しており、圧縮機の構造が簡単で、往復動冷凍機に比べて振動が小さいです。"}, {"id": 51, "q": "ヒートポンプ方式では、空気熱源方式に比べて水熱源方式の方が成績係数が高い。", "answer": true, "exp": "ヒートポンプ方式とは大気中などの熱を集めて移動させる方式であり、これににおいては空気熱源方式に比べて水熱源方式の方が成績係数が高いです。"}, {"id": 52, "q": "同じ冷凍能力の吸収冷凍機と圧縮冷凍機では、必要となる冷却塔の冷却能力は同じである。", "answer": false, "exp": "冷凍能力は同じでも、吸収冷凍機に関しては化学反応を利用する分、加熱サイクルがあるので冷却塔の冷却能力は吸収式の方が大きくなります。"}, {"id": 53, "q": "ペリメーター空気処理方式は、コールドドラフトの防止に有効である。", "answer": true, "exp": "コールドドラフトとは、冬の部屋で例えると、暖房器具で温められた部屋の空気が、冷たい窓ガラスにより冷やされ床面に下降することにより、室内の上部と下部とに大きな温度差が生じる現象をいいます。その防止策として「ペリメーター空気処理方式」があります。"}, {"id": 54, "q": "変風量単一ダクト方式は、定風量単一ダクト方式に比べて搬送動力を節減できる。", "answer": true, "exp": "変風量単一ダクト方式は、定風量単一ダクト方式に比べて「搬送動力を節減」できます。"}, {"id": 55, "q": "ファンコイルユニット・ダクト併用方式は、一般的に、全空気方式に比べて搬送動力が小さい。", "answer": true, "exp": "ー"}, {"id": 56, "q": "床吹出し方式は、天井吹出し方式に比べて暖房運転時の居住域における垂直温度差が大きい。", "answer": false, "exp": "暖房運転時において、暖かい空気は上昇するので、「床吹出し方式」は、天井吹出し方式に比べて暖房運転時の居住域における「垂直温度差」が「小さく」なります。"}, {"id": 57, "q": "サッシからの隙間風負荷は、導入外気量と排気量を調整し、室内を正圧に保つことが期待できる場合、見込まなくてよい。", "answer": true, "exp": "サッシからの隙間風負荷に関して、導入外気量と排気量を調整し、「室内を正圧に保つ」ことが期待できるなら、見込む必要がありません。"}, {"id": 58, "q": "暖房負荷計算では、一般的に、土間床、地中壁からの熱負荷は見込まなくてよい。", "answer": false, "exp": "「暖房負荷計算」において、土間床、地中壁からの熱損失はおおきいので、熱負荷は計算に見込みます。反対に「冷房負荷計算」には見込みません。"}, {"id": 59, "q": "人体負荷は、室内温度が変わっても全発熱量はほとんど変わらないが、温度が上がるほど顕熱量が小さくなり、潜熱量が大きくなる。", "answer": true, "exp": "温度が上がるほど化学変化に必要な温度＝「潜熱」は大きくなります。体が体温の上昇により冷やそうとするからです。"}, {"id": 60, "q": "外気に面したドアを有する空調対象室において、ドアからの隙間風を考慮する場合は、隙間風量を換気回数法により算定してよい。", "answer": true, "exp": "ー"}, {"id": 61, "q": "外気取入れダンパは、空気調和機の運転開始時に一定時間、閉とする。", "answer": true, "exp": "室内の空調の立ち上がりを早くする方式として、空調機起動後一定時間は加湿制御を止め、OA(外気取り入れ)とEA(排気)電動ダンパーを閉止し、リターン用電動ダンパーを開とします。"}, {"id": 62, "q": "外気取入れダンパ及び排気ダンパは、二酸化炭素濃度により比例制御とする。", "answer": true, "exp": "省エネルギーのために CO2 検出器からの信号で、OA(外気取り入れ)とEA(排気)電動ダンパーとリターン電動ダンパーを比例制御して CO2 濃度制御を行います。"}, {"id": 63, "q": "冷却塔のファンは、外気温度により二位置制御とする。", "answer": false, "exp": "冷却塔の冷却水温度制御のために、冷却水出口設置　の温度調節計で、冷却塔ファンを二位置制御(ON/OFF制御)します。"}, {"id": 64, "q": "外気冷房が有効な場合、外気取入れダンパ及び排気ダンパは、給気温度により比例制御とする。", "answer": true, "exp": "省エネルギーとして外気で室内の冷房空調の方が有効である場合には、給気温度検出器によって、OA(外気取り入れ)とEA(排気)電動ダンパーとリターン電動ダンパーを温度制御器で比例制御します。"}, {"id": 65, "q": "地域冷暖房の熱需要者側の建物は、床面積の利用率が低くなる。", "answer": false, "exp": "熱源設備を入れなくていいので床面積の利用率が下がる"}, {"id": 66, "q": "地下鉄の排熱、ゴミ焼却熱等の未利用排熱を有効に利用することが可能である。", "answer": true, "exp": "-"}, {"id": 67, "q": "建物ごとに熱源機器を設置する必要がないため、火災や騒音のおそれが小さくなる。", "answer": true, "exp": "-"}, {"id": 68, "q": "地域冷暖房の社会的な利点には、大気汚染防止効果がある。", "answer": true, "exp": "高性能な排ガス設備を入れられる。汚染箇所が１か所になり管理しやすい"}, {"id": 69, "q": "ヒートポンプでは、外気温度が低くなると暖房能力が低下する。", "answer": true, "exp": ""}, {"id": 70, "q": "ヒートポンプの成績係数は、圧縮仕事の駆動エネルギーが追加されるため、往復動冷凍機の成績係数より高くなる。", "answer": true, "exp": "ヒートポンプの成績係数εh は、εh＝ε+1となり、同じ条件の冷凍機の成績係数より1高くなります。"}, {"id": 71, "q": "ヒートポンプの除霜運転は、一般的に、四方弁を冷房サイクルに切り替えて行う。", "answer": true, "exp": "四方切換え弁は、冷暖房サイクルを逆にする効果があり、冷房サイクルに切り替えることで室外用空気熱交換器に高圧・高温のガスを流して除湿を行います。"}, {"id": 72, "q": "ヒートポンプでは、外気温度が低くなると蒸発圧力、蒸発温度が高くなる。", "answer": false, "exp": "外が寒いと、空気から奪える熱が少ない→ 冷媒もあまり熱をもらえない→ 蒸発しにくくなる→ だから蒸発温度・圧力は下がる"}, {"id": 73, "q": "集会所等の用途に供する特殊建築物の居室において、床面積の 1/20 以上の換気上有効な開口部を有する場合、換気設備を設けなくてもよい。", "answer": false, "exp": "集会所等の用途に供する特殊建築物の居室においては、　窓などの換気上有効な開口部がある場合でも機械換気設備または、中央管理方式の空気調和設備が必要になります。\n一般建築物の居室では、床面積の1/20以上の窓その他の開口があれば、換気設備は設けなくて構いません。"}, {"id": 74, "q": "密閉式燃焼器具のみを設けた室には、火気を使用する室としての換気設備を設けなくてもよい。", "answer": true, "exp": "密閉式燃焼器具のみを設けた室には、火気を使用する室としての換気設備を設けなくてもよいです。"}, {"id": 75, "q": "発熱量の合計が６kW以下の火を使用する設備又は器具を設けた室（調理室を除く。）は、換気上有効な開口部を有する場合、火気を使用する室としての換気設備を設けなくてもよい。", "answer": true, "exp": "「発熱量の合計が６kW以下」「換気上有効な開口部を有する」換気不要"}, {"id": 76, "q": "自然換気設備の排気口は、給気口より高い位置に設け、常時解放された構造とし、かつ、排気筒の立ち上がり部分に直結する必要がある。", "answer": true, "exp": "「自然換気設備の排気口」に関して、「給気口より高い位置」に設け、「常時解放」された構造とし、かつ、「排気筒の立ち上がり部分に直結」する必要があります。"}, {"id": 77, "q": "自然排煙口は、防煙区画部分の床面積の 1/50 以上の排煙上有効な開口面積を有する必要がある。", "answer": true, "exp": "また、機械排煙は防煙区画の床面積 1 m² につき1 m³/min 以上必要です。"}, {"id": 78, "q": "排煙立てダクト（メインダクト）の風量は、最遠の階から順次比較し、各階ごとの排煙風量のうち大きい方の風量とする。", "answer": true, "exp": "-"}, {"id": 79, "q": "防煙垂れ壁は、防火戸上部及び天井チャンバー方式を除き、天井面より40 cm以上下方に突出した不燃材料で造られたものとする。", "answer": false, "exp": "防煙垂れ壁は、天井面より 50 cm 以上下方に突出した不燃材料で造られたものとする必要があります。"}, {"id": 80, "q": "排煙機は、多翼形、軸流形等、一般の送風機に使用されている機種を用いるが、サージングやオーバーロードがないように排煙ダクト系に合う機種を選定する。", "answer": true, "exp": "-"}, {"id": 81, "q": "排煙立てダクト（メインダクト）には、原則として、防火ダンパを設けない。", "answer": true, "exp": "排煙立てダクト（メインダクト）には、原則として、防火ダンパを設けません。メインダクトに設けてしまったら作動した時に煙の逃げ場がなくなるからです。"}, {"id": 82, "q": "２以上の防煙区画を対象とする場合の排煙風量は、１分間に120 m3以上で、かつ、最大防煙区画の床面積１m2につき２m3以上とする。", "answer": true, "exp": "「２以上」の防煙区画を対象とする場合の排煙風量は、「１分間に120㎥以上」で、かつ、最大防煙区画の「床面積１㎥につき２㎥以上」とします。"}, {"id": 83, "q": "電源を必要とする排煙設備の予備電源は、20分間継続して排煙設備を作動できる容量とし、かつ、常用の電源が断たれた場合に自動的に切り替えられるものとする。", "answer": false, "exp": "電源を必要とする排煙設備の「予備電源」に関してですが、「30分間継続」して排煙設備を作動できる容量とし、かつ常用の電源が断たれた場合に「自動的に切り替えられる」ものとします。"}, {"id": 84, "q": "同一防煙区画に複数の排煙口を設ける場合は、排煙口の１つを開放することで他の排煙口を同時に開放する連動機構付とする。", "answer": true, "exp": "同一防煙区画に複数の排煙口を設ける場合は、排煙口の１つを開放することで他の排煙口を同時に開放する「連動機構付」とします。"}, {"id": 85, "q": "給水管を分岐する箇所での配水管内の動水圧は、0.1 MPaを標準とする。", "answer": false, "exp": "配水管から給水管を分岐する箇所での配水管内の「動水圧」は、0.15 MPa以上すること、さらに静水圧は0.75MPaを超えないこととしています。"}, {"id": 86, "q": "配水管より分水栓又はサドル付分水栓によって給水管を取り出す場合は、他の給水装置の取付口から30 cm以上離す。", "answer": true, "exp": "-"}, {"id": 87, "q": "配水管を他の地下埋設物と交差又は近接して敷設する場合は、少なくとも30 cm以上の間隔を保つ。", "answer": true, "exp": "-"}, {"id": 88, "q": "配水管を敷設する場合の配管の基礎は、軟弱層が深い場合、管径の 1/3 〜 1/1 程度（ 最小50 cm ）を砂又は良質土に置き換える。", "answer": true, "exp": "-"}, {"id": 89, "q": "汚水管きょの流速は、計画下水量に対し0.6 〜 3.0 m/sとする。", "answer": true, "exp": "-"}, {"id": 90, "q": "管きょの最小口径は、雨水管きょでは 150 mm、汚水管きょでは 250 mmを標準とする。", "answer": false, "exp": "雨水管きょ および 合流管きょ では 250mm,汚水管きょ では 200mm となります。"}, {"id": 91, "q": "管きょ径が変化する場合の接続方法は、原則として水面接合又は管頂接合とする。", "answer": true, "exp": "-"}, {"id": 92, "q": "管きょに取付管を接続する場合、取付管の管底が本管の中心部より上方になるように取り付ける。", "answer": true, "exp": "-"}, {"id": 93, "q": "受水タンクを設ける場合の高置タンクの容量は、一般的に、時間最大予想給水量に0.5 〜 1.0を乗じた量とする。", "answer": true, "exp": ""}, {"id": 94, "q": "給水管の管径は、ヘーゼン・ウィリアムスの式を用いて算定することができる。", "answer": true, "exp": ""}, {"id": 95, "q": "水道直結増圧ポンプの給水量は、時間平均予想給水量とする。", "answer": false, "exp": "水道直結増圧ポンプ方式で給水するということは、タンクを設けず増圧ポンプを介して直接給水する方式なので、「瞬時最大予想給水量」となります。"}, {"id": 96, "q": "受水タンクには吸込みピットを設け、タンクの底面は、ピットに向かって 1/100 程度の勾配をとる。", "answer": true, "exp": ""}, {"id": 97, "q": "衛生器具の同時使用率は、器具数が増えるほど小さくなる。", "answer": true, "exp": ""}, {"id": 98, "q": "一般水栓の最低必要吐出圧力は、30 kPaである。", "answer": true, "exp": ""}, {"id": 99, "q": "受水タンクの水抜き管は、間接排水として排水口空間を設ける。", "answer": true, "exp": ""}, {"id": 100, "q": "揚水管の横引配管が長くなる場合、上層階で横引きをする方が水柱分離を生じにくい。", "answer": false, "exp": "水柱分離を起こしにくくするには、横引配管は給水圧力の高い下層階で行うべきです。\n水柱分離とは、揚水ポンプを停止して流れを急に止めたときに、慣性力と重力の作用によって管内が負圧となってしまい、局部の圧力が水の飽和蒸気圧よりも低くなることにより、蒸発を起こして水流がとぎれてしまう現象をいいます。"}, {"id": 101, "q": "中央式給湯設備の熱源に使用する真空式温水発生機の運転には、有資格者を必要としない。", "answer": true, "exp": ""}, {"id": 102, "q": "循環ポンプの揚程は、貯湯タンクから最高所の給湯栓までの配管の摩擦損失抵抗及び給湯栓の最低必要吐出圧力を考慮して求める。", "answer": false, "exp": "ポンプの吐出から最高所の給水栓までの配管に対して考慮します。"}, {"id": 103, "q": "循環式浴槽設備では、レジオネラ症防止対策のため、循環している浴槽水をシャワーや打たせ湯には使用しない。", "answer": true, "exp": ""}, {"id": 104, "q": "瞬間湯沸器の１号は、流量１L/minの水の温度を25℃上昇させる能力を表しており、加熱能力は約1.74 kWである。", "answer": true, "exp": ""}, {"id": 105, "q": "器具排水負荷単位法により通気管径を算定する場合の通気管長さは、通気管の実長に局部損失相当長を加算する。", "answer": false, "exp": "「器具排水負荷単位法」によりといっているということは通気管は器具数によって決まりますので、「局部損失相当長を加算する」は間違っています。"}, {"id": 106, "q": "結合通気管の管径は、通気立て管と排水立て管のうち、いずれか小さい方の管径以上とする。", "answer": true, "exp": ""}, {"id": 107, "q": "建物の階層が多い場合の最下階の排水横枝管は、排水立て管に接続せず、単独で排水桝に接続する。", "answer": true, "exp": ""}, {"id": 108, "q": "排水立て管に45度を超えるオフセットを設ける場合、オフセットの上部及び下部 600 mm以内には排水横枝管を接続しない。", "answer": true, "exp": ""}, {"id": 109, "q": "通気立て管の上部は、管径を縮小せずに延長し、大気に開放する。", "answer": true, "exp": ""}, {"id": 110, "q": "トラップ桝は、50 〜 100 mmの封水深を確保できるものとする。", "answer": true, "exp": ""}, {"id": 111, "q": "管径 150 mmの排水横主管には、掃除口を30 mごとに取り付ける。", "answer": true, "exp": "100ｍｍ以下は15ｍ,100ｍｍを超える場合は30ｍ"}, {"id": 112, "q": "特殊継手排水システムには、排水横枝管の流れを排水立て管内に円滑に流入させ、排水立て管内の流速を高める効果がある。", "answer": false, "exp": "「特殊継手排水システム」に関して、これは縦方向の水流を螺旋状にスムーズに流すことができるようにするための継手です。"}, {"id": 113, "q": "汚物ポンプは、固形物を多く含んだ水を排水するため、それに適したノンクロッグ形ポンプ、ボルテックス形ポンプ等を用いる。", "answer": true, "exp": ""}, {"id": 114, "q": "排水ポンプの排水量は、排水量が一定に近い場合、毎時平均排水量の 1.2 〜 1.5 倍とする。", "answer": true, "exp": ""}, {"id": 115, "q": "ブランチ間隔10以上を持つ排水立て管は、最上階から数えてブランチ間隔10以内に結合通気管を設ける。", "answer": true, "exp": ""}, {"id": 116, "q": "飲料用貯水タンクに設ける管径50 mmの間接排水管の排水口空間は、最小100 mmとする。", "answer": false, "exp": "「間接排水管の排水口空間」は「最小150ｍｍ」とします。飲料用貯水タンクの用途以外であれば100ｍｍでも可です。"}, {"id": 117, "q": "局所放出方式の不活性ガス消火設備は、常時人がいるおそれのある部分に設けることができる。", "answer": false, "exp": "不活性ガス消火設備とは、二酸化炭素や窒素等を混合した不活性ガスにより窒息効果にて消火を行う設備であり、水が使用できない箇所に設けられます。\n人体に有害であるガスになるので、「常時人がいるおそれのある部分に設けることができません。」"}, {"id": 118, "q": "不活性ガス消火設備を設置する防護区画には、その放出された消火剤及び燃焼ガスを安全な場所に排出するための措置を講ずる。", "answer": true, "exp": ""}, {"id": 119, "q": "不活性ガス消火設備を設置する防護区画が２以上あり、貯蔵容器を共用する場合は、防護区画ごとに選択弁を設けなければならない。", "answer": true, "exp": ""}, {"id": 120, "q": "全域放出方式又は局所放出方式に附置する非常電源は、当該設備を有効に１時間作動できる容量以上とする。", "answer": true, "exp": ""}, {"id": 121, "q": "都市ガスの種類 A・B・C における燃焼速度は、A が最も速く B・C の順で遅くなる。", "answer": false, "exp": "都市ガスにおいて、燃焼速度はAがもっとも「遅く」B、Cの順ではやくなります。"}, {"id": 122, "q": "液化天然ガスには、通常、一酸化炭素は含まれていない。", "answer": true, "exp": ""}, {"id": 123, "q": "都市ガスのガス漏れ警報器は、天井面が 0.6 m以上の梁等により区画されている場合は、燃焼器等側に設置する。", "answer": true, "exp": ""}, {"id": 124, "q": "液化石油ガス設備士でなければ、液化石油ガス配管の気密試験の作業に従事できない。", "answer": true, "exp": ""}, {"id": 125, "q": "事務所の処理対象人員は、延べ面積に、業務用厨房設備の有無により異なる定数を乗じて算定する。", "answer": true, "exp": ""}, {"id": 126, "q": "病院の処理対象人員は、ベッド数を用いて算定する。", "answer": true, "exp": ""}, {"id": 127, "q": "飲食店の処理対象人員は、延べ面積に定数を乗じて算定する。", "answer": true, "exp": ""}, {"id": 128, "q": "戸建て住宅の処理対象人員は、住宅の延べ面積により３人又は６人に区分される。", "answer": false, "exp": "延べ面積によって、5人(130m²未満)又は7人(130m²以上)とします。"}, {"id": 129, "q": "キャビテーションは、ポンプの羽根車入口部等で局部的に生じる場合があり、騒音や振動の原因となる。", "answer": true, "exp": ""}, {"id": 130, "q": "同一配管系で、同じ特性の２台のポンプを直列運転して得られる揚程は、ポンプを単独運転した場合の揚程の２倍より小さくなる。", "answer": true, "exp": ""}, {"id": 131, "q": "同一配管系で、同じ特性の２台のポンプを並列運転して得られる吐出量は、ポンプを単独運転した場合の吐出量の２倍になる。", "answer": false, "exp": "同じ特性の２台のポンプを「並列運転」していますが、単独運転した場合の揚程の２倍にとはいかず、1.4倍程度となります。"}, {"id": 132, "q": "ポンプの軸動力は回転速度の３乗に比例し、揚程は回転速度の２乗に比例する。", "answer": true, "exp": ""}, {"id": 133, "q": "密閉式冷却塔は、熱交換器などの空気抵抗が大きく、開放式冷却塔に比べて送風機動力が大きくなる。", "answer": true, "exp": ""}, {"id": 134, "q": "開放式冷却塔で使用される送風機には、風量が大きく静圧が小さい軸流送風機が使用される。", "answer": true, "exp": ""}, {"id": 135, "q": "冷却塔の微小水滴が、気流によって塔外へ飛散することをキャリーオーバーという。", "answer": true, "exp": ""}, {"id": 136, "q": "冷却塔の冷却水入口温度と出口温度の差をアプローチという。", "answer": false, "exp": "アプローチとは、冷却塔の冷却水の「出口水温」と「湿球温度」の「差」をいいます。"}, {"id": 137, "q": "スクロールダンパ方式では、回転操作ハンドルにより送風機ケーシングのスクロールの形状を変えて送風特性を変化させる。", "answer": true, "exp": ""}, {"id": 138, "q": "冷却コイルは、供給冷水温度は通常５〜７℃、コイル面通過風速は 2.5 m/s 前後で選定される。", "answer": true, "exp": ""}, {"id": 139, "q": "デシカント除湿ローターは、高温の排気と外気とを熱交換する際に外気の湿度を除去する。", "answer": true, "exp": ""}, {"id": 140, "q": "加熱コイルには温水コイルと蒸気コイルがあり、温水コイル、蒸気コイルとも冷却コイルと兼用することができる。", "answer": false, "exp": "「温水コイル」は「冷却コイル」と兼用できますが、「蒸気コイル」は「冷却コイル」との兼用はできません。"}, {"id": 141, "q": "圧力配管用炭素鋼鋼管は、350℃ 程度以下の蒸気や高温水などの圧力の高い配管に使用される。", "answer": true, "exp": ""}, {"id": 142, "q": "配管用炭素鋼鋼管の使用に適した流体の温度は、−15 〜 350℃ 程度である。", "answer": true, "exp": ""}, {"id": 143, "q": "硬質ポリ塩化ビニル管（ VP ）の設計圧力の上限は、1.0 MPa である。", "answer": true, "exp": ""}, {"id": 144, "q": "水道用硬質塩化ビニルライニング鋼管の使用に適した流体の温度は、60℃ 以下である。", "answer": false, "exp": "「水道用」硬質塩化ビニルライニング鋼管の使用に適した流体の温度は、「40℃以下」です。ちなみに使用圧力は1MPaとなります。"}, {"id": 145, "q": "低圧ダクトと高圧ダクトは、通常運転時におけるダクト内圧が正圧、負圧ともに 300 Pa で区分される。", "answer": false, "exp": "通常運転時」における、低圧ダクトのダクト内圧は正圧、負圧とも500Pa以下、高圧1の場合で、500超え1000Pa以下、－500Paを超え－1000Pa以内\n高圧2の場合で、正圧で1000超え2500Pa以下、負圧でー1000超えー2000Pa以内となります。"}, {"id": 146, "q": "定風量ユニット（ CAV ）は、上流側の圧力が変動する場合でも、風量を一定に保つ機能を持っている。", "answer": true, "exp": ""}, {"id": 147, "q": "変風量ユニット（ VAV ）は、外部からの制御信号により風量を変化させる機能を持っている。", "answer": true, "exp": ""}, {"id": 148, "q": "材料、断面積、風量が同じ場合、円形ダクトの方が長方形ダクトより単位摩擦抵抗が小さい。", "answer": true, "exp": ""}, {"id": 149, "q": "受注者は、工事現場内に搬入した材料を監督員の承諾を受けないで工事現場外に搬出してはならない。", "answer": true, "exp": ""}, {"id": 150, "q": "受注者は、工事目的物及び工事材料等を設計図書に定めるところにより、火災保険、建設工事保険等に付さなければならない。", "answer": true, "exp": ""}, {"id": 151, "q": "設計図書の表示が明確でない場合は、工事現場の状況を勘案し、受注者の判断で施工する。", "answer": false, "exp": "「監督員」に通知し、発注者と受注者と協議して工事内容、工期、請負金額を決定する必要があります。"}, {"id": 152, "q": "約款及び設計図書に特別な定めがない仮設、施工方法等は、受注者がその責任において定める。", "answer": true, "exp": ""}, {"id": 153, "q": "現場代理人は、当該工事現場に常駐してその運営取り締まりを行うほか、請負代金の変更に関する権限も付与されている。", "answer": false, "exp": ""}, {"id": 154, "q": "工事材料は、設計図書にその品質が明示されていない場合、中等の品質を有するものとする。", "answer": true, "exp": ""}, {"id": 155, "q": "施工計画書には、総合施工計画書、工種別施工計画書があり、一般的に、仮設計画や施工要領書も含まれる。", "answer": true, "exp": ""}, {"id": 156, "q": "総合工程表は、現場での仮設工事や機器製作手配から試運転調整、後片付け、清掃、検査までの全体の工程の大要を表すものである。", "answer": true, "exp": ""}, {"id": 157, "q": "振動の特定建設作業実施届 -------- 市町村長", "answer": true, "exp": ""}, {"id": 158, "q": "ばい煙発生施設設置届 ------------ 労働基準監督署長", "answer": false, "exp": "ばい煙発生施設設置届書は、都道府県知事または政令で定める市の長に、着工の60日前までに提出します。"}, {"id": 159, "q": "浄化槽設置届 -------------------- 都道府県知事（保健所を設置する市又は特別区にあっては、市長又は区長）", "answer": true, "exp": ""}, {"id": 160, "q": "工事整備対象設備等着工届 -------- 消防長又は消防署長", "answer": true, "exp": ""}, {"id": 161, "q": "工期の途中で工程計画をチェックし、現実の推移を入れて調整することをフォローアップという。", "answer": true, "exp": ""}, {"id": 162, "q": "通常考えられる標準作業時間を限界まで短縮したときの作業時間を特急作業時間（クラッシュタイム）という。", "answer": true, "exp": ""}, {"id": 163, "q": "配員計画において、割り付けた人員等の不均衡の平滑化を図っていくことを山崩しという。", "answer": true, "exp": ""}, {"id": 164, "q": "クリティカルパスに次ぐ重要な経路で、工事の日程を短縮した場合、クリティカルパスになりやすい経路をインターフェアリングフロートという。", "answer": false, "exp": "「インターフェアリングフロート」とは、後続作業のトータルフロートからフリーフロートを引いた「余裕時間」をいい、クリティカルパスに次ぐ重要な経路とはいいがたいです。"}, {"id": 165, "q": "パレート図とは、関係のある２つの対になったデータの１つを縦軸に、他の１つを横軸にとり両者の対応する点をグラフにプロットした図である。", "answer": false, "exp": "本文は「散布図」に関する説明です。パレート図の一番の特徴は、棒グラフと折れ線グラフを複合したグラフであり、左側の縦軸は発生頻度を表すなかで、コストやその他の重要な測定単位を表し、右側の縦軸は全体の発生件数、総コスト、特定の全測定単位に占める累積構成比を表す図です。"}, {"id": 166, "q": "パレート図では、大きな不良項目、不良項目の順位、各不良項目が全体に占める割合等を読み取ることができる。", "answer": true, "exp": ""}, {"id": 167, "q": "特性要因図とは、問題としている特性とそれに影響を与えると想定される要因の関係を魚の骨のような図に体系的に整理したものである。", "answer": true, "exp": ""}, {"id": 168, "q": "特性要因図は、不良の原因と考えられる事項が整理されるため、関係者の意見を引き出したり、改善の手段を決めたりすることに有用である。", "answer": true, "exp": ""}, {"id": 169, "q": "建設工事における品質管理とは、品質計画に基づき施工を実施し、品質を保証することである。", "answer": true, "exp": ""}, {"id": 170, "q": "建設工事は現場ごとの一品生産であることから、統計的な手法による品質管理は有効とならない。", "answer": false, "exp": "「統計的な手法による品質管理」は一品生産であったとしても、過去の統計が生きていくこともあるので有効です。"}, {"id": 171, "q": "建設工事における品質管理の効果には、施工品質の向上、施工不良やクレームの減少等がある。", "answer": true, "exp": ""}, {"id": 172, "q": "建設工事における日常の品質管理には、異常が出たときの処置や、問題解決と再発防止も含まれる。", "answer": true, "exp": ""}, {"id": 173, "q": "重大災害とは、一時に３人以上の労働者が業務上死亡した災害をいい、労働者が負傷又はり病した災害は含まない。", "answer": false, "exp": "重大災害の定義に関してですが、重大災害とは不休も含む一時に3人以上の労働者が業務上死傷又はり病した災害をいいます。"}, {"id": 174, "q": "建設工事において発生件数の多い労働災害には、墜落・転落災害、建設機械・クレーン災害、土砂崩壊・倒壊災害がある。", "answer": true, "exp": ""}, {"id": 175, "q": "災害の発生頻度を示す度数率とは、延べ実労働時間 100万時間当たりの労働災害による死傷者数である。", "answer": true, "exp": ""}, {"id": 176, "q": "災害の規模及び程度を示す強度率とは、延べ実労働時間 1,000時間当たりの労働災害による労働損失日数である。", "answer": true, "exp": ""}, {"id": 177, "q": "屋内でアーク溶接作業を行う場合は、粉じん障害を防止するため、全体換気装置による換気の実施又はこれと同等以上の措置を講じる。", "answer": true, "exp": ""}, {"id": 178, "q": "導電体に囲まれた著しく狭隘な場所で、交流アーク溶接等の作業を行うときは、自動溶接の場合を除き、交流アーク溶接機用自動電撃防止装置は使用しない。", "answer": false, "exp": "導電体に囲まれた著しく狭隘な場所で、交流アーク溶接等の作業を行うときは、自動溶接の場合を除き、交流アーク溶接機用自動電撃防止装置を使用する。"}, {"id": 179, "q": "リスクアセスメントとは、潜在する労働災害のリスクを評価し、当該リスクの低減対策を実施することである。", "answer": true, "exp": ""}, {"id": 180, "q": "リスクアセスメントの実施においては、個々の事業場における労働者の就業に係るすべての危険性又は有害性が対象となる。", "answer": true, "exp": ""}, {"id": 181, "q": "１日の冷凍能力が法定 50トン未満の冷凍機の据付けにおいて、冷凍機の操作盤前面の空間距離は、大型ボイラー等に面する場合を除き、1.2 m としてよい。", "answer": true, "exp": ""}, {"id": 182, "q": "屋内設置の飲料用受水タンクの据付けにおいて、コンクリート基礎上の鋼製架台の高さを 100 mm とする場合、コンクリート基礎の高さは 500 mm としてよい。", "answer": true, "exp": ""}, {"id": 183, "q": "呼び番号３の送風機の設置において、４方向に振れ止めを設ける場合、天井から吊りボルトにより吊り下げてよい。", "answer": false, "exp": "天井から吊りボルトにより吊り下げてよい送風機の呼び番号は2、2と1/2以下までです。"}, {"id": 184, "q": "雑排水用水中モーターポンプ２台を排水槽内に設置する場合、ポンプケーシングの中心間距離は、ポンプケーシングの直径の３倍としてよい。", "answer": true, "exp": ""}, {"id": 185, "q": "貯湯タンクの据付けにおいては、周囲に 450 mm 以上の保守・点検スペースを確保するほか、加熱コイルの引抜きスペース及び内部点検用マンホール部分のスペースを確保する。", "answer": true, "exp": ""}, {"id": 186, "q": "防振基礎に設ける耐震ストッパは、地震時における機器の横移動の自由度を確保するため、機器本体との間の隙間を極力大きくとって取り付ける。", "answer": false, "exp": "防振基礎に設ける耐震ストッパに関して、機器本体との間の隙間を横移動が確保が可能な範囲内で「できるだけ少なく」とる、が正解となります。"}, {"id": 187, "q": "あと施工アンカーの設置においては、所定の許容引抜き力を確保するため、使用するドリルにせん孔する深さの位置をマーキングして所定のせん孔深さを確保する。", "answer": true, "exp": ""}, {"id": 188, "q": "天井スラブの下面において、あと施工アンカーを上向きに設置する場合、接着系アンカーは使用しない。", "answer": true, "exp": ""}, {"id": 189, "q": "空気調和機への冷温水量を調整する混合型電動３方弁は、一般的に、空調機コイルからの還り管に設ける。", "answer": true, "exp": ""}, {"id": 190, "q": "空気調和機への冷温水配管の接続では、往き管を空調機コイルの下部接続口に、還り管を上部接続口に接続する。", "answer": true, "exp": ""}, {"id": 191, "q": "冷温水配管からの膨張管を開放形膨張タンクに接続する際は、接続口の直近にメンテナンス用バルブを設ける。", "answer": false, "exp": "冷温水配管からの膨張管を開放形膨張タンクに接続する場合に関して、接続口の直近ではなく、「配管本体」上に設けます。"}, {"id": 192, "q": "複数の空気調和機に冷温水を供給する冷温水配管において、各空気調和機を通る経路の摩擦損失抵抗を等しくする方式にリバースリターン方式がある。", "answer": true, "exp": ""}, {"id": 193, "q": "ポンプの振動が防振継手により配管と絶縁されている場合は、配管の防振支持の検討は不要である。", "answer": false, "exp": "ポンプの振動が防振継手により配管と絶縁されている場合ですが、それだけではポンプ自身の振動により配管の破損の原因となってしまします。フレキシブル管の採用もですが、配管の防振支持の検討は必要となります。"}, {"id": 194, "q": "配管の防振支持に吊り形の防振ゴムを使用する場合は、防振ゴムに加わる力の方向が鉛直下向きとなるようにする。", "answer": true, "exp": ""}, {"id": 195, "q": "強制循環式の下向き給湯配管では、給湯管、返湯管とも先下がりとし、勾配は 1/200 以上とする。", "answer": true, "exp": ""}, {"id": 196, "q": "通気横走り管を通気立て管に接続する場合は、通気立て管に向かって上り勾配とし、配管途中で鳥居配管や逆鳥居配管とならないようにする。", "answer": true, "exp": ""}, {"id": 197, "q": "亜鉛鉄板製スパイラルダクトは、亜鉛鉄板をらせん状に甲はぜ機械掛けしたもので、高圧ダクトにも使用できる。", "answer": true, "exp": ""}, {"id": 198, "q": "横走りの主ダクトに設ける振れ止め支持の支持間隔は 12 m 以下とするが、梁貫通箇所等の振れを防止できる箇所は振れ止め支持とみなしてよい。", "answer": true, "exp": ""}, {"id": 199, "q": "立てダクトの支持は１フロア１か所とするが、階高が４m を超える場合には中間に支持を追加する。", "answer": true, "exp": ""}, {"id": 200, "q": "サプライチャンバーやレタンチャンバーの点検口の扉は、原則として、チャンバー内が正圧の場合は外開き、負圧の場合は内開きとする。", "answer": false, "exp": "正圧の場合には内開き、負圧となる場合は外開きとします。"}, {"id": 201, "q": "長方形ダクトの分岐には、一般的に、割込み分岐に比べて加工が容易な片テーパ付き直付け分岐が用いられる。", "answer": true, "exp": ""}, {"id": 202, "q": "直径 500 mm 以下のスパイラルダクトの吊り金物には、棒鋼にかえて亜鉛鉄板を帯状に加工したバンドを使用してもよい。", "answer": false, "exp": "スパイラルダクトの吊り金物に、棒鋼にかえて亜鉛鉄板を帯状に加工したバンドを使用してもよい場合は「直径300ｍｍ以下」のスパイラルダクトに関してです。"}, {"id": 203, "q": "長方形ダクトの直角エルボには案内羽根を設け、案内羽根の板厚はダクトの板厚と同じ厚さとする。", "answer": true, "exp": ""}, {"id": 204, "q": "パネル形の排煙口は、排煙ダクトの気流方向とパネルの回転軸が平行となる向きに取り付ける。", "answer": true, "exp": ""}, {"id": 205, "q": "ステンレス鋼板製（ SUS444製を除く。）貯湯タンクを保温する際は、タンク本体にエポキシ系塗装等を施すことにより、タンク本体と保温材とを絶縁する。", "answer": true, "exp": ""}, {"id": 206, "q": "ポリスチレンフォーム保温筒を冷水管の保温に使用する場合、保温筒１本につき２か所以上粘着テープ巻きを行うことにより、合わせ目の粘着テープ止めは省略できる。", "answer": false, "exp": "「ポリスチレンフォーム保温筒」に関して、「冷水管」の保温に使用する場合は、保温筒１本につき「合わせ目をすべて粘着テープ止め」、さらに「継ぎ目は粘着テープ2回巻き」とします。"}, {"id": 207, "q": "保温を施した屋内露出配管が床を貫通する場合は、床面より少なくとも 150 mm 程度の高さまでステンレス鋼帯製バンド等で被覆する。", "answer": true, "exp": ""}, {"id": 208, "q": "JISに規定される 40K のグラスウール保温板は、32K の保温板に比較して、熱伝導率（平均温度 70℃ ）の上限値が小さい。", "answer": true, "exp": ""}, {"id": 209, "q": "溶融めっきは、金属を高温で溶融させた槽中に被処理材を浸漬したのち引き上げ、被処理材の表面に金属被覆を形成させる防食方法である。", "answer": true, "exp": ""}, {"id": 210, "q": "金属溶射は、加熱溶融した金属を圧縮空気で噴射して、被処理材の表面に金属被覆を形成させる防食方法である。", "answer": true, "exp": ""}, {"id": 211, "q": "配管の防食に使用される防食テープには、防食用ポリ塩化ビニル粘着テープ、ペトロラタム系防食テープ等がある。", "answer": true, "exp": ""}, {"id": 212, "q": "電気防食法における外部電源方式では、直流電源装置から被防食体に防食電流が流れるように、直流電源装置のプラス端子に被防食体を接続する。", "answer": false, "exp": "金属の腐食（イオン化）は電子を失うことで起こる。マイナス側には電子が蓄えられている。腐食（イオン化）を防ぐためにはマイナス側に接続します。"}, {"id": 213, "q": "冷凍機の試運転では、冷水ポンプ、冷却水ポンプ及び冷却塔が起動した後に冷凍機が起動することを確認する。", "answer": true, "exp": ""}, {"id": 214, "q": "ボイラーの試運転では、ボイラーを運転する前に、ボイラー給水ポンプ、オイルポンプ、給気ファン等の単体運転の確認を行う。", "answer": true, "exp": ""}, {"id": 215, "q": "ポンプの試運転では、軸封部がメカニカルシール方式の場合、メカニカルシールから水滴が連続滴下していることを確認する。", "answer": false, "exp": "ポンプの試運転に関して、軸封部が「メカニカルシール方式」の場合、「水漏れがないこと」を確認します。「グランドパッキン方式」の場合は、水滴が連続滴下していることを確認します。"}, {"id": 216, "q": "空気調和機の試運転では、加湿器は、空気調和機の送風機とインターロックされていることを確認する。", "answer": true, "exp": ""}, {"id": 217, "q": "特定元方事業者は、毎作業日に少なくとも１回、作業場所の巡視を行わなければならない。", "answer": true, "exp": ""}, {"id": 218, "q": "元方安全衛生管理者は、その事業場に専属の者でなければならない。", "answer": true, "exp": ""}, {"id": 219, "q": "事業場に安全委員会を設置した場合、当該安全委員会は毎月１回以上開催されなければならない。", "answer": true, "exp": ""}, {"id": 220, "q": "特定元方事業者は、安全衛生責任者を選任して、統括安全衛生責任者との連絡等を行わせなければならない。", "answer": false, "exp": "特定元方事業者は、統括安全衛生責任者を選任し、元方安全衛生管理者の指揮をさせます。"}, {"id": 221, "q": "事務所用途の建築物の二酸化炭素排出量をライフサイクルでみると、一般的に、設計・建設段階、運用段階、改修段階、廃棄段階のうち、設計・建設段階が全体の過半を占めている。", "answer": false, "exp": "運用段階"}, {"id": 222, "q": "代替フロンであるHFCは、オゾン層を破壊しないが、地球の温暖化に影響を与える程度を示す地球温暖化係数（GWP）は二酸化炭素より大きい。", "answer": true, "exp": ""}, {"id": 223, "q": "酸性雨は、大気中の硫黄酸化物や窒素酸化物が溶け込んで酸性となった雨のことで、湖沼や森林の生態系へ悪影響を与えるほか、建築構造物にも被害を与える。", "answer": true, "exp": ""}, {"id": 224, "q": "ZEBとは、大幅な省エネルギー化の実現と再生可能エネルギーの導入により、室内環境の質を維持しつつ年間一次エネルギー消費量の収支をゼロとすることを目指した建築物のことである。", "answer": true, "exp": ""}, {"id": 225, "q": "室内側より屋外側の面積が大きくなる建物出隅部分は、他の部分に比べ室内側の表面温度が低下するため、表面結露を生じやすい。", "answer": true, "exp": ""}, {"id": 226, "q": "窓ガラス表面の結露対策として、カーテンを掛け、窓ガラスを露出させないことが有効である。", "answer": false, "exp": ""}, {"id": 227, "q": "繊維系断熱材を施した外壁における内部結露を防止するため、断熱材の室内側に防湿層を設ける。", "answer": true, "exp": ""}, {"id": 228, "q": "外壁を構成する仕上げ材の内部空隙における水蒸気分圧を、その点における飽和水蒸気圧より低くすると、内部結露を防止することができる。", "answer": true, "exp": ""}, {"id": 229, "q": "ヒ素、六価クロム化合物等の重金属は毒性が強く、水質汚濁防止法に基づく有害物質として排水基準が定められている。", "answer": true, "exp": ""}, {"id": 230, "q": "BODは、河川等の水質汚濁の指標として用いられ、主に水中に含まれる有機物が酸化剤で化学的に酸化したときに消費する酸素量をいう。", "answer": false, "exp": "微生物が有機物を酸化分解するために必要な酸素の量"}, {"id": 231, "q": "ノルマルヘキサン抽出物質含有量は、油脂類による水質汚濁の指標として用いられ、ヘキサンで抽出される油分等の物質量をいう。", "answer": true, "exp": ""}, {"id": 232, "q": "TOCは、水の汚染度を判断する指標として用いられ、水中に存在する有機物中の炭素量をいう。", "answer": true, "exp": ""}, {"id": 233, "q": "キャビテーションとは、流体の静圧が局部的に飽和蒸気圧より低下し、気泡が発生する現象をいう。", "answer": true, "exp": ""}, {"id": 234, "q": "カルマン渦とは、一様な流れの中に置いた円柱等の下流側に交互に発生する渦のことをいう。", "answer": true, "exp": ""}, {"id": 235, "q": "流体の粘性による摩擦応力の影響は、一般的に、物体の表面近くで顕著に現れる。", "answer": true, "exp": ""}, {"id": 236, "q": "粘性流体の運動に影響を及ぼす動粘性係数は、粘性係数を流体の速度で除した値である。", "answer": false, "exp": "「動粘性係数」は、粘性係数を流体の「密度」で除（÷）した値です。"}, {"id": 237, "q": "ダルシー・ワイスバッハの式 ―――― 圧力損失", "answer": true, "exp": ""}, {"id": 238, "q": "ベンチュリー管 ―――――――――― 流量測定", "answer": true, "exp": ""}, {"id": 239, "q": "トリチェリの定理 ――――――――― 毛管現象", "answer": false, "exp": "トリチェリの定理は、容器に入れた水が、容器の下に空けた穴から流れ出る流速が、容器の高さに重力加速度を掛けた値のルート値に比例するという定理です。"}, {"id": 240, "q": "ウォーターハンマー ―――――――― 水柱分離", "answer": true, "exp": ""}, {"id": 241, "q": "固体や液体では、定圧比熱と定容比熱はほぼ同じ値である。", "answer": true, "exp": "固体と液体では、両者の比熱の間にはほとんど差がありませんが、気体ではその差が大きく、常に定圧比熱が大きく次のように表されます。Cp－Cv＝RRはガス定数です。"}, {"id": 242, "q": "気体を断熱圧縮させた場合、その温度は上昇する。", "answer": true, "exp": ""}, {"id": 243, "q": "結晶が等方性を有する固体の体膨張係数は、線膨張係数のほぼ3倍である。", "answer": true, "exp": ""}, {"id": 244, "q": "圧縮式冷凍サイクルでは、蒸発温度を低くすれば、成績係数は大きくなる。", "answer": false, "exp": "圧縮式であるなら、蒸発温度を低くした場合成績係数は「小さく」なります。"}, {"id": 245, "q": "等質な固体壁内部における熱伝導による熱移動量は、その固体壁内の温度勾配に比例する。", "answer": true, "exp": ""}, {"id": 246, "q": "自然対流は、流体の密度の差により生じる浮力により、上昇流や下降流が起こることで生じる。", "answer": true, "exp": ""}, {"id": 247, "q": "物体から放出される放射熱量は、その物体の絶対温度の4乗に比例する。", "answer": true, "exp": ""}, {"id": 248, "q": "固体壁表面の熱伝達率の大きさは、固体壁表面に当たる気流の影響を受けない。", "answer": false, "exp": "固体壁表面に当たる気流の影響はおおいに受けます。壁表面にあたる風速が大きいほど大きくなります。つまりは速く冷めるということです。"}, {"id": 249, "q": "湿り空気を固体吸着減湿器（シリカゲル）で減湿する場合、湿り空気の状態変化は、一般的に、乾球温度一定の変化としてよい。", "answer": false, "exp": "湿り空気を固体吸着減湿器（シリカゲル）で減湿する、といっています。この場合湿り空気中の水分をシリカゲルにて吸着、吸収する際には熱が発生します。それによって乾球温度が上がる→相対湿度が下がる、という仕組みになります。"}, {"id": 250, "q": "湿り空気を水噴霧加湿器で加湿する場合、湿り空気の状態変化は、近似的に湿球温度一定の変化としてよい。", "answer": true, "exp": ""}, {"id": 251, "q": "湿り空気を蒸気加湿器で加湿する場合、湿り空気の状態変化における熱水分比は、水蒸気の比エンタルピーと同じ値としてよい。", "answer": true, "exp": ""}, {"id": 252, "q": "熱水分比とは、湿り空気の状態変化における比エンタルピーの変化量の絶対湿度の変化量に対する比をいう。", "answer": true, "exp": ""}, {"id": 253, "q": "同じ音圧レベルの2つの音を合成すると、音圧レベルは約3dB大きくなる。", "answer": true, "exp": ""}, {"id": 254, "q": "人の可聴範囲は、周波数では概ね20〜20,000Hzであるが、同じ音圧レベルの音であっても3,000〜4,000Hz付近の音が最も大きく聞こえる。", "answer": true, "exp": ""}, {"id": 255, "q": "NC曲線で示される音圧レベルの許容値は、周波数が高いほど大きい。", "answer": false, "exp": "NC曲線は、騒音に対する評価指標で、騒音を分析して、周波数別に音圧レベルの許容値を示す曲線図です。NC曲線では、低温になるほど高いレベルが許容されるが、周波数が高くなり程、音圧レベルの許容値が下降します。"}, {"id": 256, "q": "点音源から放射された音が球面状に一様に広がる場合、音源からの距離が2倍になると音圧レベルは約6dB低下する。", "answer": true, "exp": ""}, {"id": 257, "q": "厨房内の電動機用配線工事において、金属管と金属製ボックスを接続するボンド線（裸銅線）を省略する。", "answer": false, "exp": "金属管と金属製ボックスを接続するボンド線は省略する事はできません。\n金属管とボックスを電気的に完全に接続し漏電による感電を防ぐ事が目的です。その際、各材料を電気的に接続するときはボンド線が使われます。"}, {"id": 258, "q": "三相3線200Vの電動機用配線工事において、金属管にD種接地工事を施す。", "answer": true, "exp": ""}, {"id": 259, "q": "合成樹脂で被覆した機械器具に接続する三相3線200Vの電路において、漏電遮断器（ELCB）を省略する。", "answer": true, "exp": ""}, {"id": 260, "q": "CD管（合成樹脂製可とう電線管）を直接コンクリートに埋め込んで施設する。", "answer": true, "exp": ""}, {"id": 261, "q": "過負荷及び欠相を保護する回路に、保護継電器と電磁接触器を組み合わせて使用する。", "answer": true, "exp": ""}, {"id": 262, "q": "配線用遮断器と電磁開閉器を組み合わせた回路において、過負荷に対して、電磁開閉器より配線用遮断器が先に動作するように設定する。", "answer": false, "exp": "配線用遮断器と電磁開閉器を組み合わせた回路において、過負荷に対して、電磁開閉器の方が配線用遮断器より先に動作するように設定する。MCが先に保護する"}, {"id": 263, "q": "スターデルタ始動の冷却水ポンプの回路に、過負荷・欠相保護継電器（2Eリレー）を使用する。", "answer": true, "exp": ""}, {"id": 264, "q": "全電圧始動（直入始動）の水中モーターポンプの回路に、過負荷・欠相・反相保護継電器（3Eリレー）を使用する。", "answer": true, "exp": ""}, {"id": 265, "q": "壁の開口補強には、鉄筋に代えて溶接金網を使用することができる。", "answer": true, "exp": ""}, {"id": 266, "q": "小さな壁開口が密集している場合、その全体を大きな開口とみなして開口補強を行うことができる。", "answer": true, "exp": ""}, {"id": 267, "q": "梁貫通孔の径の大きさは、梁せいの1/3以下とする。", "answer": true, "exp": ""}, {"id": 268, "q": "2つの大きさの異なる梁貫通孔の中心間隔は、梁貫通孔の径の平均値の2倍以上とする。", "answer": false, "exp": "2つの大きさの異なる梁貫通孔の中心間隔に関してですが、梁貫通孔の径の平均値の「３倍以上」となります。"}, {"id": 269, "q": "窓は、ひさし、高遮熱ガラス、ブラインド等による日射遮へい性能の高いものを採用し、日射熱取得を減らす。", "answer": true, "exp": ""}, {"id": 270, "q": "建物の平面形状は、東西面を長辺とした場合、長辺の短辺に対する比率を大きくする。", "answer": false, "exp": "空調システムの省エネルギーにおける建物の平面計画では南北方向を長くすることで効率はよくなります。東西面を長辺とした場合は、長辺の短辺に対する比率を「小さく」するべきです。"}, {"id": 271, "q": "屋上緑化は、植物や土壌による熱の遮断だけでなく、屋外空間の温度上昇を緩和する効果がある。", "answer": true, "exp": ""}, {"id": 272, "q": "外壁の塗装には、赤外線を反射し、建物の温度上昇を抑制する効果のある塗料を採用する。", "answer": true, "exp": ""}, {"id": 273, "q": "定風量単一ダクト方式は、送風温度を変化させるため、各室の負荷変動パターンが異なる建物の空調に適している。", "answer": false, "exp": "定風量単一ダクト方式は、温度・湿度を調整した一定風量を各室に送るため、各室の負荷変動パターンが異なる建物の空調には適していない。"}, {"id": 274, "q": "大温度差送風（低温送風）方式は、送風量の低減によりダクトサイズを小さくすることができる。", "answer": true, "exp": ""}, {"id": 275, "q": "床吹き出し方式は、居住域空間を効率的に空調することができるが、冷房運転時には室内の垂直温度差が大きくなる。", "answer": true, "exp": ""}, {"id": 276, "q": "天井放射冷房方式は、ドラフトが生じないため快適性が高いが、結露防止に配慮する必要がある。", "answer": true, "exp": ""}, {"id": 277, "q": "人体からの発熱量は、室内温度が下がると顕熱分が大きくなり、潜熱分が小さくなる。", "answer": true, "exp": "顕熱とは、温度が上昇や下降する際に変化する熱をいいます。潜熱とは、化学変化（蒸発、融解、凝縮、凝固など）だけで温度の変わらない熱をいいます。\nですので、本文のとおり人体からの発熱量は、室内温度が下がると顕熱分が大きくなり、潜熱分が小さくなります。"}, {"id": 278, "q": "土間床、地中壁からの通過熱負荷は、一般的に、年中熱損失側であるため無視する。", "answer": true, "exp": ""}, {"id": 279, "q": "北面のガラス窓からの日射負荷は、一般的に、直達日射が当たらないため無視する。", "answer": false, "exp": "北面のガラス窓からの日射負荷は夏季の西日（15時から19時）の影響を大いに受けるので考慮が必要になります。"}, {"id": 280, "q": "日射及び夜間放射の影響を受ける外壁の負荷計算には、通常の温度差の代わりに、実効温度差を用いる。", "answer": true, "exp": ""}, {"id": 281, "q": "空気調和機の冷温水コイルの制御弁 ――― 空気調和機入口空気の温度", "answer": false, "exp": "空気調和機の冷温水コイルの制御弁は空気調和機「出口」空気の温度を検出し、制御します。"}, {"id": 282, "q": "VAVユニット ――――――――――――― 空調室内の温度", "answer": true, "exp": ""}, {"id": 283, "q": "外気及び排気用電動ダンパー ―――――― 還気ダクト内の二酸化炭素濃度", "answer": true, "exp": ""}, {"id": 284, "q": "空気調和機のファン ―――――――――― VAVユニットの風量", "answer": true, "exp": ""}, {"id": 285, "q": "受電並列運転（系統連系）は、コージェネレーションシステムによる電力を商用電力と接続し、一体的に電力を供給する方式である。", "answer": true, "exp": ""}, {"id": 286, "q": "燃料電池を用いるシステムは、原動機式と比べて発電効率が高く、騒音や振動が小さい。", "answer": true, "exp": ""}, {"id": 287, "q": "熱機関からの排熱は、高温から低温に向けて順次多段階に活用するように計画する。", "answer": true, "exp": ""}, {"id": 288, "q": "マイクロガスタービン発電機を用いたシステムでは、工事、維持、運用に係る保安の監督を行う者として、ボイラー・タービン主任技術者の選任が必要である。", "answer": false, "exp": "マイクロガスタービン発電機（発電量20ｋｗから300ｋｗ）を用いたシステム、と述べています。小型のガスタービン発電設備（出力300ｋｗ未満など）は、ボイラー・タービン主任技術者の選任が「不要」です。"}, {"id": 289, "q": "蓄熱を利用した空調方式では、ピークカットにより熱源機器の容量を低減することができる。", "answer": true, "exp": ""}, {"id": 290, "q": "二次側配管系を開放回路とした場合、ポンプの揚程には循環の摩擦損失のほかに押上げ揚程が加わるため、ポンプの動力が大きくなる。", "answer": true, "exp": ""}, {"id": 291, "q": "氷蓄熱方式は、氷の融解潜熱を利用するため、水蓄熱方式に比べて蓄熱槽の容量が大きくなる。", "answer": false, "exp": "氷蓄熱方式は、水蓄熱方式に氷から水への溶融潜熱が付加され、多くの冷熱を小さな蓄熱槽に蓄える方式です。"}, {"id": 292, "q": "蓄熱槽を利用することで、熱源機器を低効率で連続運転することがなくなり、最適な効率で運転できる。", "answer": true, "exp": ""}, {"id": 293, "q": "開放式燃焼器具を使用した調理室は、燃焼空気の供給のため、機械換気で室内を正圧にする。", "answer": false, "exp": "・給気口と排気口の位置などの構造と、開放式燃焼器具の場合に、排気口に設置する換気扇等について規定しています。\n・排気設備は、第1種機械換気から第3種機械換気まであり、給気口と、排気口に設置する換気扇は、第3種機械換気です。(法規では、機械設備の選択は決められていません。)\n大規模な厨房の場合は、第1種とすべきでしょうが、問題では家庭の調理室程度の大きさと考えられるため、第3種とします。\n・第3種機械換気では、室内は負圧になります。\n・施行令に基づく告示では、排気量は40KQ以上と決められています。"}, {"id": 294, "q": "喫煙室は、発生する有害ガスや粉じんを除去し、室外に拡散させないため、空気清浄機を設置し、機械換気で室内を負圧にする。", "answer": true, "exp": ""}, {"id": 295, "q": "火気使用室の換気を自然換気方式で行う場合、排気筒の有効断面積は、燃料の燃焼に伴う理論廃ガス量、排気筒の高さ等から算出する。", "answer": true, "exp": ""}, {"id": 296, "q": "エレベーター機械室の換気は、熱の除去が主な目的であり、サーモスタットにて換気ファンの発停を行い、室温が許容値以下となるようにする。", "answer": true, "exp": ""}, {"id": 297, "q": "排煙ダクトに設ける防火ダンパーは、作動温度280℃のものを使用する。", "answer": true, "exp": ""}, {"id": 298, "q": "同一の防煙区画において、自然排煙と機械排煙を併用してはならない。", "answer": true, "exp": ""}, {"id": 299, "q": "常時開放型の排煙口は、2以上の防煙区画を1台の排煙機で受け持つ場合に適した形式である。", "answer": false, "exp": "常時開放型の排煙口の目的は「自然排煙口」としてです。排煙機で受け持つ機械排煙口には適していません。"}, {"id": 300, "q": "同一防煙区画内に可動間仕切りがある場合、間仕切られる室それぞれに排煙口を設け連動させる。", "answer": true, "exp": ""}, {"id": 301, "q": "排煙設備が設置対象となる建築物において、一般事務室の防煙区画の床面積は、1,000m2以下とする。", "answer": false, "exp": "排煙設備が設置対象となる建築物における、「一般事務室（一般建築物）」の防煙区画の床面積は「500㎡以下」です。これはおさえておいてください。"}, {"id": 302, "q": "天井高さが3m以上の居室に設ける排煙口は、床面からの高さが2.1m以上で、かつ天井高さの1／2以上の壁の部分に設けることができる。", "answer": true, "exp": ""}, {"id": 303, "q": "排煙口の位置は、避難方向と煙の流れが反対になるように配置する。", "answer": true, "exp": ""}, {"id": 304, "q": "高さ31mを超える建築物における排煙設備の制御及び作動状態の監視は、中央管理室において行うことができるものとする。", "answer": true, "exp": ""}, {"id": 305, "q": "2階建て建物への直結の給水を確保するためには、配水管の最小動水圧は0.15〜0.2MPaを標準とする。", "answer": true, "exp": ""}, {"id": 306, "q": "伸縮自在でない継手を用いた管路の露出配管部には、40〜50mの間隔で伸縮継手を設ける。", "answer": false, "exp": "伸縮継手の設ける間隔は10～20ｍ程度が正解です。管の素材によって伸縮率は違うため計算により算出しますが一般的には10～20ｍ程度です。"}, {"id": 307, "q": "公道に埋設する配水管の土被りは、1.2mを標準とする。", "answer": true, "exp": ""}, {"id": 308, "q": "公道に埋設する外径80mm以上の配水管には、原則として、占用物件の名称、管理者名、埋設した年等を明示するテープを取り付ける。", "answer": true, "exp": ""}, {"id": 309, "q": "合流式の下水道では、降雨の規模によっては、処理施設を経ない下水が公共用水域に放流されることがある。", "answer": true, "exp": ""}, {"id": 310, "q": "地表勾配が急な場合の管きょの接合は、原則として、地表勾配に応じて段差接合又は階段接合とする。", "answer": true, "exp": ""}, {"id": 311, "q": "硬質塩化ビニル管、強化プラスチック複合管等の可とう性のある管きょの基礎は、原則として、自由支承の砂又は砕石基礎とする。", "answer": true, "exp": ""}, {"id": 312, "q": "分流式の下水道において、管きょ内の必要最小流速は、雨水管きょに比べて、汚水管きょの方が大きい。", "answer": false, "exp": "汚水管きょの最小流速は、0.6m/sec雨水管きょ及び合流管きょの最小流速は、0.8m/secですので雨水管きょのほうが大きくなります。"}, {"id": 313, "q": "給水量の算定をする場合、1人1日当たりの単位給水量は、事務所の方が集合住宅より多い。", "answer": false, "exp": "集合住宅は、台所、浴室、便所、洗面所と給水箇所があるのであきらかに事務所より多くなります。"}, {"id": 314, "q": "受水タンクには、地震時の対応として緊急遮断弁を設ける。", "answer": true, "exp": ""}, {"id": 315, "q": "高置タンク方式における揚水ポンプの揚水量は、時間最大予想給水量に基づき決定する。", "answer": true, "exp": ""}, {"id": 316, "q": "受水タンクの容量は、一般的に、1日予想給水量の半分程度とする。", "answer": true, "exp": ""}, {"id": 317, "q": "高層建築物では、高層部、低層部等の給水系統のゾーニング等により、給水圧力が400〜500kPaを超えないようにする。", "answer": true, "exp": ""}, {"id": 318, "q": "揚水ポンプの吐出側の逆止め弁は、揚程が30mを超える場合、ウォーターハンマーの発生を防止するため衝撃吸収式とする。", "answer": true, "exp": ""}, {"id": 319, "q": "クロスコネクションの防止対策には、飲料用とその他の配管との区分表示のほか、減圧式逆流防止装置の使用等がある。", "answer": true, "exp": ""}, {"id": 320, "q": "大気圧式のバキュームブレーカーは、常時水圧のかかる配管部分に設ける。", "answer": false, "exp": "キュームブレーカーを設ける目的は「負圧防止」です。常時水圧がかかる「正圧」配管部分には設けません。通気管のような箇所に設けます。"}, {"id": 321, "q": "中央式給湯設備の返湯管の管径は、一般的に、給湯管の1／2程度とし、循環流量から管内流速を確認して決定する。", "answer": true, "exp": ""}, {"id": 322, "q": "貯湯タンクには、加熱による水の膨張で装置全体の圧力を異常に上昇させないため、逃し管又は安全弁（逃し弁）を設ける。", "answer": true, "exp": ""}, {"id": 323, "q": "住宅のセントラル給湯に使用する瞬間式ガス湯沸器は、冬期におけるシャワーと台所の湯の同時使用、及び、浴槽の湯張り時間を考慮して、一般的に、12号程度の能力が必要である。", "answer": false, "exp": "本文のようなことまで考慮するなら、24号程度は必要になります。これはおさえておいてください。ちなみに12号程度だとシャワー単体でしかまかなえません。"}, {"id": 324, "q": "小型貫流ボイラーは、保有水量が少ないため負荷変動の追随性が良く、伝熱面積が30m2以下の場合、取扱いにボイラー技士を必要としない。", "answer": true, "exp": ""}, {"id": 325, "q": "ブランチ間隔とは、汚水又は雑排水立て管に接続する排水横枝管の垂直距離の間隔のことであり、2.5mを超える場合を1ブランチ間隔という。", "answer": true, "exp": ""}, {"id": 326, "q": "管径65mm以上の間接排水管の末端と、間接排水口のあふれ縁との排水口空間は、最小150mmとする。", "answer": true, "exp": ""}, {"id": 327, "q": "器具排水負荷単位は、大便器の排水流量を標準に、器具の同時使用率等を考慮して定められたものである。", "answer": false, "exp": "器具排水負荷単位とは、「洗面器」の排水流量を標準に「1」とした負荷単位です。ちなみに大便器の排水負荷単位は4です。"}, {"id": 328, "q": "グリース阻集器の容量算定には、阻集グリースの質量、たい積残さの質量及び阻集グリースの掃除周期を考慮する。", "answer": true, "exp": ""}, {"id": 329, "q": "通気立て管の上部は、管径を縮小せずに延長し、上端は単独で大気に開放するか、最高位の衛生器具のあふれ縁より150mm以上立ち上げて伸頂通気管に接続する。", "answer": true, "exp": ""}, {"id": 330, "q": "通気管の開口部が、建物の出入り口、窓、換気口等の付近にある場合は、水平距離で600mm以上離す。", "answer": false, "exp": "通気管の開口部が、建物の出入り口、窓、換気口等の付近にある場合、「水平距離」であるなら「3ｍ以上」離します。開口部の上端からの距離は「600ｍｍ以上」離します。"}, {"id": 331, "q": "各個通気管の取り出し位置は、器具トラップのウェアから管径の2倍以上離れた位置とする。", "answer": true, "exp": ""}, {"id": 332, "q": "排水横枝管に分岐がある場合は、それぞれの排水横枝管に通気管を設ける。", "answer": true, "exp": ""}, {"id": 333, "q": "排水槽の容量は、一般的に、流入排水の負荷変動、ポンプの最短運転時間、槽内貯留時間等を考慮して決定する。", "answer": true, "exp": ""}, {"id": 334, "q": "通気弁は、大気開口された伸頂通気のような正圧緩和の効果がないため、排水槽の通気管末端には使用してはならない。", "answer": true, "exp": ""}, {"id": 335, "q": "排水の貯留時間が長くなるおそれがある場合は、臭気の問題等から、一定時間を経過するとタイマーでポンプを起動させる制御方法を考慮する。", "answer": true, "exp": ""}, {"id": 336, "q": "汚水用水中モーターポンプは、小さな固形物が混入した排水に用いられ、口径の40%程度の径の固形物が通過可能なものである。", "answer": false, "exp": "汚水用水中モーターポンプは、一般的な機種では、扱える固形物は大きさ20mm以下（口径40mm以下は10mm以下）を対象とします。"}, {"id": 337, "q": "水噴霧消火設備は、霧状の水の放射による冷却効果及び発生する水蒸気による窒息効果により消火するものである。", "answer": true, "exp": ""}, {"id": 338, "q": "粉末消火設備は、粉末状の消火剤を放射し、消火剤の熱分解で発生した二酸化炭素や水蒸気による窒息効果、冷却効果等により消火するものである。", "answer": true, "exp": ""}, {"id": 339, "q": "不活性ガス消火設備は、不活性ガスを放射し、ガス成分の化学反応による負触媒効果により消火するものである。", "answer": false, "exp": "「不活性ガス消火設備」に使用される不活性ガスの成分は、二酸化炭素や窒素などであり、ガス成分の化学反応による「窒息効果」により消火を行う設備で、水が使用できない電気室などに備わります。"}, {"id": 340, "q": "泡消火設備は、泡状の消火剤を放射し、燃焼物を泡の層で覆い、窒息効果と冷却効果により消火するものである。", "answer": true, "exp": ""}, {"id": 341, "q": "内容積が20L以上の液化石油ガスの容器を設置する場合は、容器の設置位置から2m以内にある火気を遮る措置を行う。", "answer": true, "exp": ""}, {"id": 342, "q": "特定地下室等に都市ガスのガス漏れ警報器を設置する場合、導管の外壁貫通部より10m以内に設置する。", "answer": false, "exp": "特定地下室等に「都市ガス」のガス漏れ警報器を設置する場合です。ポイントは都市ガスは空気より「軽い」ものになるので、導管の外壁貫通部より「8m以内」に設置することのなります。空気より「重い」とされる「LPガス」の場合は「4ｍ以内」となります。"}, {"id": 343, "q": "一般消費者等に供給される液化石油ガスは、「い号」、「ろ号」、「は号」に区分され、「い号」が最もプロパン及びプロピレンの合計量の含有率が高い。", "answer": true, "exp": ""}, {"id": 344, "q": "液化プロパンが気化した場合のプロパンの密度は、標準状態で約2kg／m3である。", "answer": true, "exp": ""}, {"id": 345, "q": "地下水位が高い場所に設置する場合は、浄化槽本体の浮上防止対策を講ずる。", "answer": true, "exp": ""}, {"id": 346, "q": "浄化槽の水平は、水準器、槽内に示されている水準目安線等で確認する。", "answer": true, "exp": ""}, {"id": 347, "q": "浄化槽本体の設置にあたって、据付け高さの調整は、山砂を用いて行う。", "answer": false, "exp": "山砂を用いるのは、「埋戻し」作業においてです。据付け高さの調整は主にコンクリートのスラブにて調整します。"}, {"id": 348, "q": "浄化槽の設置工事を行う場合は、浄化槽設備士が実地に監督する。", "answer": true, "exp": ""}, {"id": 349, "q": "流入水が高負荷の場合、生物膜の肥厚が早くなるため、長時間ばっ気方式に比べて、浄化機能を保ちやすい。", "answer": false, "exp": "流入水が高負荷の場合、生物膜の肥厚が早くなると長時間ばっ気方式に比べて、浄化機能を保ちにくくなります。"}, {"id": 350, "q": "出現する生物の種類が多く、比較的大型の生物が発生するため、長時間ばっ気方式に比べて、汚泥発生量はやや少なくなる。", "answer": true, "exp": ""}, {"id": 351, "q": "生物膜のはく離と移送が生物管理の主たる作業となるため、長時間ばっ気方式に比べて、生物管理は容易である。", "answer": true, "exp": ""}, {"id": 352, "q": "接触材に生物が付着しているため、長時間ばっ気方式に比べて、水量変動の影響はあまり受けない。", "answer": true, "exp": ""}, {"id": 353, "q": "ボイラー本体は、ガスや油の燃焼を行わせる燃焼室と、燃焼ガスとの接触伝熱によって熱を吸収する対流伝熱面で構成される。", "answer": true, "exp": ""}, {"id": 354, "q": "鋳鉄製ボイラーは、鋼製ボイラーに比べて急激な温度変化に弱いが、高温、高圧、大容量のものの製作が可能である。", "answer": false, "exp": "鋳鉄製ボイラーは、急激な温度変化に弱く、強度的に脆いので高圧・大容量に向きません。鋳鉄製ボイラーの利点は、セクション毎に分割可能なので、組み立て、解体、搬入に便利であり、腐食に強いという点です。"}, {"id": 355, "q": "真空式温水発生機は、運転中の内部圧力が大気圧より低いため、「労働安全衛生法」におけるボイラーに該当せず、取扱いにボイラー技士を必要としない。", "answer": true, "exp": ""}, {"id": 356, "q": "炉筒煙管ボイラーは、胴内部に炉筒（燃焼室）と多数の煙管を配置したもので、胴内のボイラー水は煙管内を通過する燃焼ガスで加熱される。", "answer": true, "exp": ""}, {"id": 357, "q": "ロックウール保温材は、グラスウール保温材より使用温度の上限が低い。", "answer": false, "exp": "ロックウール保温材の使用温度上限は700℃以上ありますが、グラスウール保温材の使用温度上限に関しては400℃程度となっています。これは原材料がロックウールは鉱物、グラスウールはガラス繊維だということに起因します。"}, {"id": 358, "q": "ポリエチレンフォーム保温材には、板状又は筒状に発泡成形したものや、板又はシート状に発泡した後に筒状に加工したものがある。", "answer": true, "exp": ""}, {"id": 359, "q": "保冷とは、常温以下の物体を被覆し侵入熱量を小さくすること、又は、被覆後の表面温度を露点温度以上とし表面に結露を生じさせないことである。", "answer": true, "exp": ""}, {"id": 360, "q": "ロックウール保温材のブランケットは、密度により1号と2号に区分される。", "answer": true, "exp": ""}, {"id": 361, "q": "多翼送風機は、高い圧力を出すことはできないが、他の遠心送風機に比べて、小型で大風量を扱うことができるため、空調用として広く用いられる。", "answer": true, "exp": ""}, {"id": 362, "q": "横流送風機は、羽根車の軸方向の長さを変えることで風量の増減が可能で、エアカーテン等に利用される。", "answer": true, "exp": ""}, {"id": 363, "q": "斜流送風機の軸動力は、風量の変化に対してほぼ変わらず、圧力曲線の山の付近で最大となるリミットロード特性を持つ。", "answer": true, "exp": ""}, {"id": 364, "q": "軸流送風機にはプロペラ型、チューブラ型、ベーン型があり、プロペラ型が最も効率がよく、高圧力に対応できる。", "answer": false, "exp": "軸流送風機に関して、正しくは「ベーン型」が最も効率が良く、チューブラ型、プロペラ型と続きます。"}, {"id": 365, "q": "排水用硬質塩化ビニルライニング鋼管の接合には、排水鋼管用可とう継手のほか、ねじ込み式排水管継手が用いられる。", "answer": false, "exp": "排水用「硬質塩化ビニルライニング」鋼管の接合とあります。この場合可とう継手は正解ですが、ねじ込み式だと内面被覆と管の端部に影響が出るので防食継手を用います。"}, {"id": 366, "q": "鋼管とステンレス鋼管等、イオン化傾向が大きく異なる異種金属管の接合には、絶縁フランジを使用する。", "answer": true, "exp": ""}, {"id": 367, "q": "架橋ポリエチレン管は、中密度・高密度ポリエチレンを架橋反応させることで、耐熱性、耐クリープ性を向上させた配管である。", "answer": true, "exp": ""}, {"id": 368, "q": "圧力配管用炭素鋼鋼管（黒管）は、蒸気、高温水等の圧力の高い配管に使用され、スケジュール番号により管の厚さが区分されている。", "answer": true, "exp": ""}, {"id": 369, "q": "吸込口へ向かう気流は、吹出口からの気流のような指向性はなく、前面から一様に吸込口へ向かう気流となるため、可動羽根や風向調節ベーン等は不要である。", "answer": true, "exp": ""}, {"id": 370, "q": "スパイラルダクトは、亜鉛鉄板をスパイラル状に甲はぜ機械がけしたもので、甲はぜが補強の役目を果たすため補強は不要である。", "answer": true, "exp": ""}, {"id": 371, "q": "たわみ継手は、たわみ部が負圧になる場合、正圧部が全圧300Paを超える場合等には、補強用のピアノ線が挿入されたものを使用する。", "answer": true, "exp": ""}, {"id": 372, "q": "等摩擦法（定圧法）で寸法を決定したダクトでは、各吹出口に至るダクトの長さが著しく異なる場合でも、各吹出口での圧力差は生じにくい。", "answer": false, "exp": "「各吹出口に至るダクトの長さが著しく異なる場合」といっています。その場合ダクトの大きさは大いに異なります。送風機の動力も大きくなったり不安定です。もちろん圧力差も大きく生じます。"}, {"id": 373, "q": "発注者が設計図書を変更し、請負代金額が2／3以上減少した場合、受注者は契約を解除することができる。", "answer": true, "exp": ""}, {"id": 374, "q": "発注者は完成検査合格後、受注者から請負代金の支払い請求があったときは、請求を受けた日から30日以内に請負代金を支払わなければならない。", "answer": false, "exp": "「発注者」は「完成検査合格後」、受注者から請負代金の支払い請求があったときは、請求を受けた日から「40日以内」に請負代金を支払わなければなない、が正解になります。"}, {"id": 375, "q": "受注者は、請負代金内訳書に健康保険、厚生年金保険及び雇用保険に係る法定福利費を明示するものとする。", "answer": true, "exp": ""}, {"id": 376, "q": "発注者は、受注者が正当な理由なく、工事に着手すべき期日を過ぎても工事に着手しないときは、必要な手続きを経た後、契約を解除することができる。", "answer": true, "exp": ""}, {"id": 377, "q": "配管用ステンレス鋼鋼管は、一般配管用ステンレス鋼鋼管に比べて、管の肉厚が厚く、ねじ加工が可能である。", "answer": true, "exp": ""}, {"id": 378, "q": "一般配管用ステンレス鋼鋼管は、給水、給湯、冷温水、蒸気還水等の配管に用いる。", "answer": true, "exp": ""}, {"id": 379, "q": "硬質ポリ塩化ビニル管には、VP、VM、VUの3種類があり、設計圧力の上限が最も低いものはVMである。", "answer": false, "exp": "硬質ポリ塩化ビニル管に関して、VP、VM、VUの3種類がありますが、設計圧力は,VP　1.0MPa,VM　0.8MPa,VU　0.6MPa　となっており、VUがいちばん低いものです。"}, {"id": 380, "q": "水道用硬質ポリ塩化ビニル管のVP及びHIVPの最高使用圧力は、同じである。", "answer": true, "exp": ""}, {"id": 381, "q": "工事目的物を完成させるための施工方法は、設計図書等に特別の定めがない限り、受注者の責任において定めなければならない。", "answer": true, "exp": ""}, {"id": 382, "q": "予測できなかった大規模地下埋設物の撤去に要する費用は、設計図書等に特別の定めがない限り、受注者の負担としなくてもよい。", "answer": true, "exp": ""}, {"id": 383, "q": "総合施工計画書は受注者の責任において作成されるが、設計図書等に特記された事項については監督員の承諾を受けなければならない。", "answer": true, "exp": ""}, {"id": 384, "q": "受注者は、設計図書等に基づく請負代金内訳書及び実行予算書を、工事契約の締結後遅滞なく発注者に提出しなければならない。", "answer": false, "exp": "実行予算書を発注者に提出する必要などありません。実行予算書は受注者側の原価管理であるものです。"}, {"id": 385, "q": "（申請書等）労働安全衛生法における第一種圧力容器設置届　　（提出時期）工事開始の30日前まで　　（提出先）労働基準監督署長", "answer": true, "exp": ""}, {"id": 386, "q": "（申請書等）消防法における指定数量以上の危険物貯蔵所設置許可申請書　　（提出時期）着工前　　（提出先）消防長又は消防署長", "answer": false, "exp": "消防法における「指定数量以上の危険物貯蔵所設置許可申請書」は「着工前」までに「市町村長」へ提出します。消防法とでてくるのでひっかけのパターンですね。"}, {"id": 387, "q": "（申請書等）道路法における道路の占用許可申請書　　（提出時期）着工前　　（提出先）道路管理者", "answer": true, "exp": ""}, {"id": 388, "q": "(申請書等）建設工事に係る資材の再資源化等に関する法律における対象建設工事の届出　　（提出時期）工事着手の7日前まで　　（提出先）都道府県知事", "answer": true, "exp": ""}, {"id": 389, "q": "手持資源等の制約のもとで工期を計画全体の所定の期間に合わせるために調整することをスケジューリングという。", "answer": true, "exp": ""}, {"id": 390, "q": "ネットワーク工程表は、作業内容を矢線で表示するアロー形と丸で表示するイベント形に大別することができる。", "answer": true, "exp": ""}, {"id": 391, "q": "ネットワーク工程表において日程短縮を検討する際は、日程短縮によりトータルフロートが負となる作業について作業日数の短縮を検討する。", "answer": true, "exp": ""}, {"id": 392, "q": "ネットワーク工程表において日程短縮を検討する際は、直列作業を並行作業に変更したり、作業の順序を変更したりしてはならない。", "answer": false, "exp": "直列作業を並行作業に変更したり、作業の順序を変更したりすることは、ネットワーク工程表において日程短縮を検討する手段の方法です。"}, {"id": 393, "q": "品質管理において、品質の向上と工事原価の低減は、常にトレードオフの関係にある。", "answer": false, "exp": "品質が向上すれば、原価が高くなるというのが通例ですが、工法改善や工期短縮によって原価がおさえられる場合もあります。"}, {"id": 394, "q": "PDCAサイクルは、計画 → 実施 → 確認 → 処理 → 計画のサイクルを繰り返すことであり、品質の改善に有効である。", "answer": true, "exp": ""}, {"id": 395, "q": "全数検査は、特注機器の検査、配管の水圧試験、空気調和機の試運転調整等に適用する。", "answer": true, "exp": ""}, {"id": 396, "q": "抜取検査は、合格ロットの中に、ある程度の不良品の混入が許される場合に適用する。", "answer": true, "exp": ""}, {"id": 397, "q": "高さが2m以上、6.75m以下の作業床がない箇所での作業において、胴ベルト型の墜落制止用器具を使用する場合、当該器具は一本つり胴ベルト型とする。", "answer": true, "exp": ""}, {"id": 398, "q": "ヒヤリハット活動とは、作業中に怪我をする危険を感じてヒヤリとしたこと等を報告させることにより、危険有害要因を把握し改善を図っていく活動である。", "answer": true, "exp": ""}, {"id": 399, "q": "ZD（ゼロ・ディフェクト）運動とは、作業方法のマニュアル化と作業員に対する監視を徹底することにより、労働災害ゼロを目指す運動である。", "answer": false, "exp": "商品の欠点や欠陥をゼロにすることを目指す運動です。"}, {"id": 400, "q": "安全施工サイクルとは、安全朝礼から始まり、安全ミーティング、安全巡回、安全工程打合せ、後片付け、終業時確認までの作業日ごとの安全活動サイクルのことである。", "answer": true, "exp": ""}, {"id": 401, "q": "ツールボックスミーティングは、職場安全会議ともいい、作業関係者が作業終了後に集まり、その日の作業、安全等について反省、再確認等を行う活動である。", "answer": false, "exp": "その日の作業の確認や注意点を全員で共有するために作業前に行われるミーティングのことです。"}, {"id": 402, "q": "暑さ指数（WBGT）は、気温、湿度及び輻射熱に関係する値により算出される指数で、熱中症予防のための指標である。", "answer": true, "exp": ""}, {"id": 403, "q": "不安全行動とは、手間や労力、時間やコストを省くことを優先し、労働者本人又は関係者の安全を阻害する可能性のある行動を意図的に行う行為をいう。", "answer": true, "exp": ""}, {"id": 404, "q": "4S活動とは、整理、整頓、清掃、清潔の4Sにより、安全で健康な職場づくりと生産性の向上を目指す活動である。", "answer": true, "exp": ""}, {"id": 405, "q": "低層建築物の屋上に2台の冷却塔を近接して設置する場合、2台の冷却塔は、原則として、冷却塔本体のルーバー面の高さの2倍以上離して設置する。", "answer": true, "exp": ""}, {"id": 406, "q": "横形ポンプを2台以上並べて設置する場合、各ポンプの基礎の間隔は、一般的に、500mm以上とする。", "answer": true, "exp": ""}, {"id": 407, "q": "真空又は窒素加圧状態で分割搬入した密閉型遠心冷凍機は、大気開放してから組み立て据え付ける。", "answer": false, "exp": "工場にて真空又は窒素加圧状態にして製品として製作したものなので、それを開放して組み立ててしまうと製品の保証がされません。"}, {"id": 408, "q": "大型冷凍機をコンクリート基礎に据え付ける場合、冷凍機は、基礎のコンクリートを打設後、10日が経過してから据え付ける。", "answer": true, "exp": ""}, {"id": 409, "q": "あと施工のメカニカルアンカーボルトは、めねじ形よりおねじ形の方が許容引抜き力が大きい。", "answer": true, "exp": ""}, {"id": 410, "q": "カプセル方式の接着系アンカーボルトを施工する場合、マーキング位置までアンカーボルトを埋込み後、アンカーボルトの回転により接着剤を十分攪拌する。", "answer": false, "exp": "カプセル方式の接着系アンカーボルトを施工する場合、マーキング位置まで「穿孔後」に孔内を清掃の後、カプセルを挿入し、アンカーボルトを打撃回転しながら打込む、です。"}, {"id": 411, "q": "地震時にアンカーボルトに加わる荷重は、原則として、機器を剛体とみなし、当該機器の重心の位置に水平及び鉛直の地震力が作用するものとして算定する。", "answer": true, "exp": ""}, {"id": 412, "q": "あと施工の接着系アンカーボルトの打設間隔は、呼び径の10倍以上を標準とする。", "answer": true, "exp": ""}, {"id": 413, "q": "冷温水配管の空気抜きに自動空気抜き弁を設ける場合、当該空気抜き弁は、管内が正圧になる箇所に設ける。", "answer": true, "exp": ""}, {"id": 414, "q": "冷温水配管の主管から枝管を分岐する場合、エルボを3個程度用いて、管の伸縮を吸収できるようにする。", "answer": true, "exp": ""}, {"id": 415, "q": "排水立て管に鉛直に対して45°を超えるオフセットを設ける場合、当該オフセット部には、原則として、通気管を設ける。", "answer": true, "exp": ""}, {"id": 416, "q": "冷温水横走り配管の径違い管を偏心レジューサーで接続する場合、管内の下面に段差ができないように接続する。", "answer": false, "exp": "冷温水横走り配管の径違い管を偏心レジューサーで接続する場合、管内の上面に段差ができないように接続します。上面に段差ができるとエア溜まりができたり、バックウォーターが発生し流れに影響を及ぼします。"}, {"id": 417, "q": "屋外埋設の排水管には、合流、屈曲等がない直管部であっても、管径の120倍以内に1箇所、排水桝を設ける。", "answer": true, "exp": ""}, {"id": 418, "q": "ステンレス鋼管の溶接接合は、管内にアルゴンガス又は窒素ガスを充満させてから、TIG溶接により行う。", "answer": true, "exp": ""}, {"id": 419, "q": "遠心ポンプの吸込み管は、ポンプに向かって1／100程度の下り勾配とし、管内の空気がポンプ側に抜けないようにする。", "answer": false, "exp": "遠心ポンプの吸込み管は、ポンプに向かって下り勾配ではなく上り勾配とします。ポンプに空気が入ってしまうと、ポンプは水を吸いません。吸い込み管に溜まった空気をポンプが吸ってしまわないように、吸い込み管には空気が溜まらないようにします。"}, {"id": 420, "q": "配管用炭素鋼鋼管を溶接接合する場合、管外面の余盛高さは3mm程度以下とし、それを超える余盛はグラインダー等で除去する。", "answer": true, "exp": ""}, {"id": 421, "q": "ダクトの系統において、常用圧力（通常の運転時におけるダクト内圧）が±500Paを超える部分は、高圧ダクトとする。", "answer": true, "exp": ""}, {"id": 422, "q": "送風機の吐出し口直後に風量調節ダンパーを取り付ける場合、風量調節ダンパーの軸が送風機の羽根車の軸に対し平行となるようにする。", "answer": false, "exp": "送風機の吐出し口直後に風量調節ダンパーを取り付ける場合、風量調節ダンパーの軸が送風機の羽根車の軸に対し直角となるようにします。"}, {"id": 423, "q": "亜鉛鉄板製の排煙ダクトと排煙機の接続は、原則として、たわみ継手等を介さずに、直接フランジ接合とする。", "answer": true, "exp": ""}, {"id": 424, "q": "送風機の吐出し口直後にエルボを取り付ける場合、吐出し口からエルボまでのダクトの長さは、送風機の羽根車の径の1.5倍以上とする。", "answer": true, "exp": ""}, {"id": 425, "q": "口径が600mm以上のスパイラルダクトの接続は、一般的に、フランジ継手が使用される。", "answer": true, "exp": ""}, {"id": 426, "q": "排煙ダクトに使用する亜鉛鉄板製の長方形ダクトの板厚は、高圧ダクトの板厚とする。", "answer": true, "exp": ""}, {"id": 427, "q": "シーリングディフューザー形吹出口は、最小拡散半径が重なるように配置する。", "answer": false, "exp": "シーリングディフューザー形吹出口は、部屋全体を最大拡散半径で覆い、かつ最小拡散半径が重ならないように均等に配置します。そうすることで、快適な室内環境を作れます。"}, {"id": 428, "q": "長辺が450mmを超える保温を施さない亜鉛鉄板製ダクトには、補強リブを入れる。", "answer": true, "exp": ""}, {"id": 429, "q": "スパイラルダクトの保温に帯状保温材を用いる場合は、原則として、鉄線を150mm以下のピッチでらせん状に巻き締める。", "answer": true, "exp": ""}, {"id": 430, "q": "保温材相互のすきまはできる限り少なくし、保温材の重ね部の継目は同一線上とならないようにする。", "answer": true, "exp": ""}, {"id": 431, "q": "保温材の取付けが必要な機器の扉、点検口廻りは、その開閉に支障がなく、保温効果を減じないように施工する。", "answer": true, "exp": ""}, {"id": 432, "q": "テープ巻き仕上げの重ね幅は15mm以上とし、垂直な配管の場合は、上方から下方へ巻く。", "answer": false, "exp": "テープ巻き仕上げの重ね幅は15mm以上であっていますが、垂直な配管に巻きあげる場合は「下方から上方へ」巻きます。下から巻き上がるゴミなどの侵入を防ぐためです。"}, {"id": 433, "q": "ガスだきの場合は、ガス配管の空気抜きを行い、ガス圧の調整を行う。", "answer": true, "exp": ""}, {"id": 434, "q": "煙道ダンパーを開き、炉内ガスを排出し、蒸気ボイラーの場合は、主蒸気弁を開く。", "answer": false, "exp": "煙道ダンパーを開き、炉内ガスを排出し、蒸気ボイラーの場合は、主蒸気弁は閉じておきます。"}, {"id": 435, "q": "オイルヒーターがある場合、オイルヒーターの電源を入れ、油を予熱する。", "answer": true, "exp": ""}, {"id": 436, "q": "火炎監視装置（フレームアイ）の前面をふさぎ、不着火や失火の場合のバーナー停止の作動を確認する。", "answer": true, "exp": ""}, {"id": 437, "q": "共通架台に複数個の回転機械を設置する場合、防振材は一番低い回転数に合わせて選定する。", "answer": true, "exp": ""}, {"id": 438, "q": "金属バネは、防振ゴムに比べて、一般的に、低周波数の振動の防振に優れている。", "answer": true, "exp": ""}, {"id": 439, "q": "金属バネは、減衰比が大きいため、共振時の振幅が小さく、サージング現象が起こりにくい。", "answer": false, "exp": "金属バネは、防振ゴムに比べて共振時の振れ幅が大きく、サージング（ポンプにおいては、周期的な圧力変動が生じ、吸込み側や吐出し側の配管で振動や騒音が起こる現象）が起きやすくなります。"}, {"id": 440, "q": "属バネは、防振ゴムに比べて、一般的に、耐寒性、耐熱性、耐水性、耐油性に優れている。", "answer": true, "exp": ""}, {"id": 441, "q": "特定元方事業者は、選任した統括安全衛生責任者に、安全管理者、衛生管理者等を指揮させなければならない。", "answer": false, "exp": "正しくは、「特定元方事業者は、統括安全衛生責任者を選任し、統括安全衛生責任者が元方安全衛生管理者を指揮しなければならない」となります。"}, {"id": 442, "q": "特定元方事業者は、下請を含めた現場の労働者の数が常時50人以上の場合（ずい道等の建設の仕事等を除く。）、統括安全衛生責任者を選任しなければならない。", "answer": true, "exp": ""}, {"id": 443, "q": "事業者は、常時50人以上の労働者を使用する事業場ごとに、産業医を選任しなければならない。", "answer": true, "exp": ""}, {"id": 444, "q": "事業者は、選任した産業医に、労働者の健康管理その他の厚生労働省令で定める事項を行わせなければならない。", "answer": true, "exp": ""}, {"id": 445, "q": "事業者は、高さが2m以上の作業床のない箇所でフルハーネス型墜落制止用器具を用いて行う作業に係る業務に労働者をつかせるときは、当該業務に関する特別の教育を行わなければならない。", "answer": true, "exp": ""}, {"id": 446, "q": "事業者は、作業主任者を選任したときは、当該作業主任者の氏名及びその者に行わせる事項を関係労働者に周知させなければならない。", "answer": true, "exp": ""}, {"id": 447, "q": "事業者は、研削といしの取替え又は取替え時の試運転の業務に労働者をつかせるときは、当該業務に関する特別の教育を行わなければならない。", "answer": true, "exp": ""}, {"id": 448, "q": "事業者は、作業床の高さが10m以上の高所作業車の運転（道路上を走行させる運転を除く。）の業務については、作業主任者に当該業務に従事する労働者の指揮を行わせなければならない。", "answer": false, "exp": "「作業床の高さが10m以上」の「高所作業車」の運転（道路上を走行させる運転を除く。）の業務です。これは「技能講習修了者」でなければなりません。事業者には任命責任はありますが、作業主任者に当該業務に従事する労働者の指揮を行わせる必要はありません。"}, {"id": 449, "q": "常時10人以上の労働者を使用する使用者は、就業規則を作成して所轄労働基準監督署長に届け出なければならない。", "answer": true, "exp": ""}, {"id": 450, "q": "使用者は、満18歳に満たない者を、最大積載荷重1t以上の人荷共用のエレベーターの運転業務に就かせてはならない。", "answer": false, "exp": "使用者は、満18歳に満たない者を、最大積載荷重「2ｔ以上」の人荷共用のエレベーター又は、高さが15ｍ以上のコンクリート用エレベーターの運転業務に就かせてはならない。"}, {"id": 451, "q": "使用者は、各事業場ごとに労働者名簿を、各労働者（日々雇い入れられる者を除く。）について調整し、労働者の氏名、生年月日、履歴等を記入しなければならない。", "answer": true, "exp": ""}, {"id": 452, "q": "使用者の責に帰すべき事由による休業の場合においては、使用者は、休業期間中当該労働者に、その平均賃金の100分の60以上の休業手当を支払わなければならない。", "answer": true, "exp": ""}, {"id": 453, "q": "居室の天井の高さは、2.1m以上とし、一室で天井の高さの異なる部分がある場合においては、その平均の高さによるものとする。", "answer": true, "exp": ""}, {"id": 454, "q": "建築主とは、建築物に関する工事の請負契約の注文者又は請負契約によらないで自らその工事をする者をいう。", "answer": true, "exp": ""}, {"id": 455, "q": "住宅の居室には、採光のための窓その他の開口部を設け、その採光に有効な部分の面積は、原則として、その居室の床面積に対して1／7以上とする。", "answer": true, "exp": ""}, {"id": 456, "q": "地階とは、床が地盤面下にある階で、床面から地盤面までの高さがその階の天井の高さの2／3以上のものをいう。", "answer": false, "exp": "地階とは、床が地盤面下にある階で、床面から地盤面までの高さがその階の天井の高さの1／3以上のものをいいます。"}, {"id": 457, "q": "地階を除く階数が2以上である建築物に設ける冷房設備等のダクトは、屋外に面する部分その他防火上支障がないものとして国土交通大臣が定める部分を除き、不燃材料で造らなければならない。", "answer": false, "exp": "「不燃材料で造らなければならない」ダクトは、地階を除く階数が「3以上」である建築物、「地階に居室を有する建築物」延べ面積が3000㎡を超える建築物になります。（屋外に面する部分その他防火上支障がないものとして国土交通大臣が定める部分を除きます。）"}, {"id": 458, "q": "建築物に設けるボイラーの煙突の地盤面からの高さは、ガスを使用するボイラーにあっては、原則として、9m以上としなければならない。", "answer": true, "exp": ""}, {"id": 459, "q": "開口部の少ない建築物等の換気設備において、中央管理方式の空気調和設備とは、空気を浄化し、その温度、湿度及び流量を調節して供給（排出を含む。）をすることができる設備をいう。", "answer": true, "exp": ""}, {"id": 460, "q": "通気管は、配管内の空気が屋内に漏れることを防止する装置が設けられている場合、必ずしも直接外気に衛生上有効に開放しなくてもよい。", "answer": true, "exp": ""}, {"id": 461, "q": "屋内消火栓設備の加圧送水装置に用いるポンプには、その吐出側に圧力計、吸込側に連成計を設けるものとする。", "answer": true, "exp": ""}, {"id": 462, "q": "屋内消火栓設備の加圧送水装置に用いるポンプは、直接操作による停止又は消火栓箱の直近に設けられた操作部からの遠隔操作による停止ができるものとする。", "answer": false, "exp": "ポンプは、直接操作によってのみ停止されるものであることとされています。"}, {"id": 463, "q": "屋内消火栓設備の加圧送水装置に用いるポンプには、水源水位がポンプより低い場合、専用の呼水槽を設けるものとする。", "answer": true, "exp": ""}, {"id": 464, "q": "屋内消火栓設備の加圧送水装置に用いるポンプの始動を明示する表示灯を設ける場合、当該表示灯は赤色とし、消火栓箱の内部又はその直近に設けるものとする。", "answer": true, "exp": ""}, {"id": 465, "q": "粉末消火設備は「消防法」上、消防の用に供する設備に該当する", "answer": true, "exp": ""}, {"id": 466, "q": "泡消火設備は「消防法」上、消防の用に供する設備に該当する", "answer": true, "exp": ""}, {"id": 467, "q": "連結送水管は「消防法」上、消防の用に供する設備に該当する", "answer": false, "exp": "連結送水管は消防活動上必要な施設になります。"}, {"id": 468, "q": "スプリンクラー設備は「消防法」上、消防の用に供する設備に該当する", "answer": true, "exp": ""}, {"id": 469, "q": "特定建設作業とは、建設工事として行われる作業のうち、著しい騒音を発生する作業であって、びょう打機を使用する作業等をいう。", "answer": true, "exp": ""}, {"id": 470, "q": "建設作業として行われる作業のうち、著しい騒音を発生する作業は、当該作業がその作業を開始した日に終わるものであっても、特定建設作業に該当する場合がある。", "answer": false, "exp": "騒音規制法施行令　第２条に関連します。当該作業がその作業を開始した日に終わるものは特定建設作業に該当しません。"}, {"id": 471, "q": "特定建設作業の実施の届け出は、当該特定建設作業の開始の日の7日前までに行わなければならない。", "answer": true, "exp": ""}, {"id": 472, "q": "特定建設作業を伴う建設工事を施工しようとする者は、特定建設作業の場所及び実施の期間等の事項を市町村長に届け出なければならない。", "answer": true, "exp": ""}, {"id": 473, "q": "事務所 ―――― 3,000m2は特定建築物に該当する", "answer": true, "exp": ""}, {"id": 474, "q": "百貨店 ―――― 3,000m2は特定建築物に該当する", "answer": true, "exp": ""}, {"id": 475, "q": "中学校 ―――― 8,000m2は特定建築物に該当する", "answer": true, "exp": ""}, {"id": 476, "q": "共同住宅 ――― 8,000m2は特定建築物に該当する", "answer": false, "exp": "共同住宅は一定の用途の建築物にはいりません。"}, {"id": 477, "q": "産業廃棄物管理票（マニフェスト）を交付された処分受託者は、当該処分を終了した日から10日以内に、管理票交付者に当該管理票の写しを送付しなければならない。", "answer": true, "exp": ""}, {"id": 478, "q": "排出事業者が自ら産業廃棄物を運搬する場合、その運搬車両には産業廃棄物収集運搬車である旨と、排出事業者名を表示しなければならない。", "answer": true, "exp": ""}, {"id": 479, "q": "排出事業者は、専ら再生利用の目的となる産業廃棄物のみの運搬又は処分を業として行う者に、再生利用する産業廃棄物のみの運搬又は処分を委託する場合、産業廃棄物管理票（マニフェスト）の交付を要しない。", "answer": true, "exp": ""}, {"id": 480, "q": "建築物の改築に伴って生じた廃石こうボード、木くず、繊維くずは、安定型最終処分場で処分することができる。", "answer": false, "exp": "廃石こうボード、木くず、繊維くずは、安定型でなく管理型最終処分場での処分になります。"}, {"id": 481, "q": "大気の透過率は、主に大気中に含まれる二酸化炭素の量に影響される。", "answer": false, "exp": "大気の透過率は二酸化炭素の量ではなく、大気中の水分量や汚染物質などのに影響されます。"}, {"id": 482, "q": "天空日射とは、大気成分により散乱、反射して天空の全方向から届く太陽放射をいう。", "answer": true, "exp": ""}, {"id": 483, "q": "日射の影響を温度に換算し、外気温度に加えて等価な温度にしたものを相当外気温度という。", "answer": true, "exp": ""}, {"id": 484, "q": "予想平均申告（PMV）とは、人体の熱的中立に近い状態の温冷感を予測する指標である。", "answer": true, "exp": ""}, {"id": 485, "q": "met（メット）とは、人体の代謝量を示す指標であり、椅座安静状態の代謝量1metは、単位体表面積当たり100Wである。", "answer": false, "exp": "met（メット）に関する説明ですが、確かにmet（メット）は人体の代謝量を示す指標ですが、椅座安静状態の代謝量1metは、単位体表面積当たり約58W（58W/㎡）です。"}, {"id": 486, "q": "clo（クロ）は、衣服の断熱性を示す単位で、1cloは約0.155m2・℃/Wである。", "answer": true, "exp": ""}, {"id": 487, "q": "人体は周囲空間との間で対流と放射による熱交換を行っており、これと同じ量の熱を交換する均一温度の閉鎖空間の温度を作用温度（OT）という。", "answer": true, "exp": ""}, {"id": 488, "q": "空気中の二酸化炭素濃度が20%程度以上になると、人体に致命的な影響を与える。", "answer": true, "exp": ""}, {"id": 489, "q": "空気中の一酸化炭素濃度が2%になると、20分程度で人体に頭痛、目まいが生じる。", "answer": false, "exp": "一酸化炭素（CO）は無味無臭の気体で極めて毒性が強く、空気中における濃度が0.02%（200ppm）に上昇すると頭痛などが起こり、さらに、濃度が上がると吐き気、めまいなどの中毒症状が進み、最悪の場合、死に至るなど身体に大きな影響を与えます。"}, {"id": 490, "q": "燃焼において、酸素濃度が19%に低下すると、不完全燃焼により急速に一酸化炭素が発生する。", "answer": true, "exp": ""}, {"id": 491, "q": "人体からの二酸化炭素発生量は、その人の作業状態によって変化し、代謝量が多くなると増加する。", "answer": true, "exp": ""}, {"id": 492, "q": "ニュートン流体では、摩擦応力は境界面と垂直方向の速度勾配に動粘性係数を乗じたものとなる。", "answer": false, "exp": "「ニュートン流体」とは、直線の流れの「せん断応力」と「速度勾配」が「比例関係」にある流体のことをいいます。ニュートン流体での摩擦応力は、「速度勾配」に比例しています。"}, {"id": 493, "q": "空気の粘性係数は、一定の圧力のもとでは、温度の上昇とともに大きくなる。", "answer": true, "exp": ""}, {"id": 494, "q": "レイノルズ数は、流体に作用する慣性力と粘性力の比で表される無次元数で、流体の平均流速に比例する。", "answer": true, "exp": ""}, {"id": 495, "q": "任意の点の速度、圧力等のすべての状態が時間的に変化しない流れを定常流という。", "answer": true, "exp": ""}, {"id": 496, "q": "強制対流熱伝達とは、外的駆動力による強制対流時の流体と壁面の間の熱移動現象をいう。", "answer": true, "exp": ""}, {"id": 497, "q": "固体内の熱移動には、高温部と低温部の温度差による熱伝導と放射による熱伝達がある。", "answer": false, "exp": "固体内の熱移動には、直接触れ高温部から低温部へ熱が移動する熱伝導、ストーブのように熱移動する熱放射、気体や流体の流れに乗り熱移動する対流があります。この3つを熱移動の三原則と言います。"}, {"id": 498, "q": "固体壁両側の気体間の熱通過による熱移動量は、気体の温度差と固体壁の面積に比例する。", "answer": true, "exp": ""}, {"id": 499, "q": "熱放射は、電磁波によって熱エネルギーが移動するため、熱を伝える物質は不要である。", "answer": true, "exp": ""}, {"id": 500, "q": "気体燃料、液体燃料、固体燃料のうち、燃焼に最も多く空気を必要とするのは固体燃料である。", "answer": true, "exp": ""}, {"id": 501, "q": "高発熱量とは、燃焼ガスに含まれる水蒸気が凝縮したときに得られる潜熱を含めた発熱量をいい、低発熱量とは、潜熱を含まない発熱量をいう。", "answer": true, "exp": ""}, {"id": 502, "q": "燃焼ガス中の窒素酸化物の量は、高温燃焼時より低温燃焼時のほうが多い。", "answer": false, "exp": "窒素酸化物は燃料に含まれる窒素化合物や空気中の窒素が高温燃焼時に酸化されることにより発生します。"}, {"id": 503, "q": "空気過剰率が大きすぎると廃ガスの持ち去る熱による損失が多くなる。", "answer": true, "exp": ""}];
